UPDATE words SET example_en_2 = 'She felt responsible for keeping the family together.', example_ko_2 = '그녀는 가족을 하나로 묶어두는 것에 책임감을 느꼈어요.', example_en_3 = 'He is a very responsible father who is always present.', example_ko_3 = '그는 항상 곁에 있는 매우 책임감 있는 아버지예요.', example_en_4 = 'Teaching kids to be responsible builds their confidence.', example_ko_4 = '아이들에게 책임감을 가르치면 자신감이 길러져요.', example_en_5 = 'Being responsible at home sets a good example for children.', example_ko_5 = '가정에서 책임감 있는 모습을 보이면 아이들에게 좋은 본보기가 돼요.' WHERE id = 'w_family_A2_31';
