UPDATE words SET example_en_2 = 'The family is slowly healing after the loss of their mother.', example_ko_2 = '가족은 어머니를 잃은 후 서서히 회복하고 있어요.', example_en_3 = 'Sharing memories helps ease the pain of loss.', example_ko_3 = '추억을 나누는 것이 상실의 고통을 완화하는 데 도움이 돼요.', example_en_4 = 'His loss left a space in the family that could not be filled.', example_ko_4 = '그의 상실은 채울 수 없는 공간을 가족 안에 남겼어요.', example_en_5 = 'Learning to live with loss is one of life''s hardest lessons.', example_ko_5 = '상실과 함께 살아가는 법을 배우는 것은 인생에서 가장 힘든 교훈 중 하나예요.' WHERE id = 'w_family_A2_35';

