UPDATE words SET example_en_2 = 'The nuclear family model became common after World War II.', example_ko_2 = '핵가족 모델은 제2차 세계 대전 이후 일반화됐어요.', example_en_3 = 'She grew up in a small nuclear family of four.', example_ko_3 = '그녀는 4인 소규모 핵가족 안에서 자랐어요.', example_en_4 = 'Not every nuclear family fits the same mould.', example_ko_4 = '모든 핵가족이 같은 틀에 맞는 것은 아니에요.', example_en_5 = 'The idea of the nuclear family is different across cultures.', example_ko_5 = '핵가족 개념은 문화마다 달라요.' WHERE id = 'w_family_B1_10';
UPDATE words SET example_en_2 = 'Her extended family lived in several different countries.', example_ko_2 = '그녀의 대가족은 여러 나라에 나뉘어 살았어요.', example_en_3 = 'The extended family gathered every New Year for a big meal.', example_ko_3 = '대가족은 매년 새해에 큰 식사를 위해 모였어요.', example_en_4 = 'Growing up in an extended family teaches you about diverse relationships.', example_ko_4 = '대가족 안에서 자라면 다양한 관계에 대해 배울 수 있어요.', example_en_5 = 'Having an extended family nearby is a great source of support.', example_ko_5 = '대가족이 근처에 있으면 큰 지지의 원천이 돼요.' WHERE id = 'w_family_B1_11';
UPDATE words SET example_en_2 = 'Both parents agreed to share custody of their two children.', example_ko_2 = '두 부모는 두 자녀의 양육권을 나누기로 합의했어요.', example_en_3 = 'Joint custody arrangements require good communication between parents.', example_ko_3 = '공동 양육권 합의는 부모 간의 좋은 소통이 필요해요.', example_en_4 = 'The custody battle was long and emotionally draining.', example_ko_4 = '양육권 분쟁은 길고 감정적으로 지치는 일이었어요.', example_en_5 = 'The children spend alternate weeks with each parent under the custody agreement.', example_ko_5 = '아이들은 양육권 합의에 따라 각 부모와 번갈아가며 주를 보내요.' WHERE id = 'w_family_B1_12';
UPDATE words SET example_en_2 = 'Her upbringing in a religious household shaped her values deeply.', example_ko_2 = '종교적 가정에서의 성장 환경이 그녀의 가치관을 깊이 형성했어요.', example_en_3 = 'His upbringing was strict but full of love and stability.', example_ko_3 = '그의 성장 환경은 엄격하지만 사랑과 안정으로 가득했어요.', example_en_4 = 'Children from different upbringings can still become close friends.', example_ko_4 = '다른 성장 환경을 가진 아이들도 좋은 친구가 될 수 있어요.', example_en_5 = 'She often reflects on her upbringing and how it shaped her.', example_ko_5 = '그녀는 자신의 성장 환경과 그것이 자신을 어떻게 형성했는지 자주 돌아봐요.' WHERE id = 'w_family_B1_13';
UPDATE words SET example_en_2 = 'She believed in firm but kind discipline for her children.', example_ko_2 = '그녀는 자녀들에게 단호하지만 친절한 훈육을 믿었어요.', example_en_3 = 'Discipline at home helps children behave well in public too.', example_ko_3 = '가정에서의 훈육은 아이들이 공공장소에서도 잘 행동하는 데 도움이 돼요.', example_en_4 = 'He struggled with discipline after his wife went back to work.', example_ko_4 = '아내가 복직한 후 그는 훈육에 어려움을 겪었어요.', example_en_5 = 'Children need consistent discipline to feel safe and secure.', example_ko_5 = '아이들은 안전하고 안정된 느낌을 갖기 위해 일관된 훈육이 필요해요.' WHERE id = 'w_family_B1_14';
UPDATE words SET example_en_2 = 'She practiced great patience when her toddler was upset.', example_ko_2 = '그녀는 유아가 속상해할 때 큰 인내심을 발휘했어요.', example_en_3 = 'Learning patience is one of the biggest lessons of parenthood.', example_ko_3 = '인내심을 배우는 것은 부모가 되는 것의 가장 큰 교훈 중 하나예요.', example_en_4 = 'He showed remarkable patience while caring for his elderly mother.', example_ko_4 = '그는 연로하신 어머니를 돌보면서 놀라운 인내심을 보여줬어요.', example_en_5 = 'Patience within a family makes difficult conversations easier.', example_ko_5 = '가족 내의 인내심은 어려운 대화를 더 쉽게 만들어줘요.' WHERE id = 'w_family_B1_15';
UPDATE words SET example_en_2 = 'He expressed his affection for his children through small gestures.', example_ko_2 = '그는 작은 몸짓으로 자녀들에 대한 애정을 표현했어요.', example_en_3 = 'Children who receive affection early tend to have better self-esteem.', example_ko_3 = '어린 시절 애정을 받은 아이들은 자존감이 더 좋은 경향이 있어요.', example_en_4 = 'Her affection for her sister was clear for everyone to see.', example_ko_4 = '언니에 대한 그녀의 애정은 누구나 볼 수 있을 만큼 분명했어요.', example_en_5 = 'Showing affection openly is an important part of healthy family life.', example_ko_5 = '솔직하게 애정을 표현하는 것은 건강한 가족생활의 중요한 부분이에요.' WHERE id = 'w_family_B1_16';
UPDATE words SET example_en_2 = 'He felt estranged from his family after moving abroad.', example_ko_2 = '그는 해외로 이사한 후 가족과 소원해진 느낌을 받았어요.', example_en_3 = 'She tried to reconnect with her estranged father before it was too late.', example_ko_3 = '그녀는 너무 늦기 전에 소원해진 아버지와 다시 연결하려고 노력했어요.', example_en_4 = 'Feeling estranged from family is one of the most painful experiences.', example_ko_4 = '가족과 소원해진 느낌을 받는 것은 가장 고통스러운 경험 중 하나예요.', example_en_5 = 'They were estranged for years but finally made peace.', example_ko_5 = '그들은 수년간 소원하게 지냈지만 마침내 화해했어요.' WHERE id = 'w_family_B1_17';
UPDATE words SET example_en_2 = 'Her daughter''s first word was a milestone the whole family celebrated.', example_ko_2 = '딸의 첫 마디는 온 가족이 축하한 이정표였어요.', example_en_3 = 'Each child reaches milestones at their own pace.', example_ko_3 = '각 아이는 자신의 속도로 이정표에 도달해요.', example_en_4 = 'Graduation is a major milestone in any family''s story.', example_ko_4 = '졸업은 모든 가족의 이야기에서 중요한 이정표예요.', example_en_5 = 'Parents often mark milestones with photos and celebrations.', example_ko_5 = '부모들은 종종 사진과 축하로 이정표를 기념해요.' WHERE id = 'w_family_B1_18';
UPDATE words SET example_en_2 = 'She has always admired her mother''s patience and grace.', example_ko_2 = '그녀는 항상 어머니의 인내심과 우아함을 존경했어요.', example_en_3 = 'Children who admire their parents are more likely to follow their values.', example_ko_3 = '부모를 존경하는 아이들은 그들의 가치관을 따를 가능성이 더 높아요.', example_en_4 = 'He admired his grandfather''s work ethic and dedication.', example_ko_4 = '그는 할아버지의 직업 윤리와 헌신을 존경했어요.', example_en_5 = 'She openly admired her sister and told her so often.', example_ko_5 = '그녀는 공개적으로 언니를 존경했고 그 마음을 자주 전했어요.' WHERE id = 'w_family_B1_19';
UPDATE words SET example_en_2 = 'She learned traditional cooking as part of her cultural heritage.', example_ko_2 = '그녀는 문화적 유산의 일환으로 전통 요리를 배웠어요.', example_en_3 = 'He is proud of his heritage and shares it with his children.', example_ko_3 = '그는 자신의 유산을 자랑스러워하고 자녀들과 나눠요.', example_en_4 = 'Their heritage connects them to generations who came before.', example_ko_4 = '그들의 유산은 그들을 이전 세대들과 연결해줘요.', example_en_5 = 'Language is one of the most powerful expressions of family heritage.', example_ko_5 = '언어는 가족 유산의 가장 강력한 표현 중 하나예요.' WHERE id = 'w_family_B1_20';
UPDATE words SET example_en_2 = 'Her parents made many sacrifices so she could study abroad.', example_ko_2 = '부모님은 그녀가 유학할 수 있도록 많은 희생을 하셨어요.', example_en_3 = 'Sacrifice is a natural part of being a loving parent.', example_ko_3 = '희생은 사랑하는 부모가 되는 것의 자연스러운 부분이에요.', example_en_4 = 'She never forgot the sacrifices her grandparents made for the family.', example_ko_4 = '그녀는 조부모님이 가족을 위해 하신 희생을 결코 잊지 않았어요.', example_en_5 = 'Children do not always understand the sacrifices their parents make.', example_ko_5 = '아이들은 부모가 하는 희생을 항상 이해하지는 못해요.' WHERE id = 'w_family_B1_21';
UPDATE words SET example_en_2 = 'Regular family dinners strengthen the bonding between members.', example_ko_2 = '정기적인 가족 식사는 구성원들 사이의 유대감 형성을 강화해요.', example_en_3 = 'She cherishes the bonding time she has with her siblings.', example_ko_3 = '그녀는 형제자매들과의 유대감 형성 시간을 소중히 여겨요.', example_en_4 = 'Good bonding in the early years helps a child feel secure.', example_ko_4 = '초기 몇 년간의 좋은 유대감 형성은 아이가 안정감을 느끼게 도와줘요.', example_en_5 = 'Shared activities are one of the best ways to encourage family bonding.', example_ko_5 = '공유된 활동은 가족 유대감 형성을 촉진하는 가장 좋은 방법 중 하나예요.' WHERE id = 'w_family_B1_22';
UPDATE words SET example_en_2 = 'She nurtured her daughter''s love of music from an early age.', example_ko_2 = '그녀는 어린 시절부터 딸의 음악 사랑을 키워줬어요.', example_en_3 = 'Parents nurture children by providing emotional as well as physical care.', example_ko_3 = '부모는 신체적 돌봄뿐 아니라 정서적 돌봄도 제공하며 자녀를 양육해요.', example_en_4 = 'He was nurtured by a grandmother who believed in his potential.', example_ko_4 = '그는 그의 잠재력을 믿어준 할머니 손에서 양육됐어요.', example_en_5 = 'Good teachers and parents both nurture a child''s growth.', example_ko_5 = '좋은 교사와 부모 모두 아이의 성장을 키워줘요.' WHERE id = 'w_family_B1_23';
UPDATE words SET example_en_2 = 'She read many books on parenting before her first child was born.', example_ko_2 = '그녀는 첫 아이가 태어나기 전에 양육에 관한 책을 많이 읽었어요.', example_en_3 = 'Good parenting involves listening as much as guiding.', example_ko_3 = '좋은 양육에는 이끄는 것만큼 들어주는 것도 포함돼요.', example_en_4 = 'Parenting styles vary widely across different cultures.', example_ko_4 = '양육 방식은 다양한 문화권에 따라 크게 달라요.', example_en_5 = 'She found parenting challenging but incredibly rewarding.', example_ko_5 = '그녀는 양육이 힘들지만 믿을 수 없을 만큼 보람 있다고 느꼈어요.' WHERE id = 'w_family_B1_24';
UPDATE words SET example_en_2 = 'The family argued over how to divide the inheritance fairly.', example_ko_2 = '가족은 유산을 공정하게 나누는 방법에 대해 논쟁했어요.', example_en_3 = 'She received a modest inheritance that helped her buy a home.', example_ko_3 = '그녀는 집을 구입하는 데 도움이 된 소박한 유산을 받았어요.', example_en_4 = 'He chose to donate his inheritance to charity.', example_ko_4 = '그는 유산을 자선단체에 기부하기로 했어요.', example_en_5 = 'Family disputes over inheritance can damage relationships permanently.', example_ko_5 = '유산을 둘러싼 가족 분쟁은 관계를 영구적으로 해칠 수 있어요.' WHERE id = 'w_family_B1_25';
UPDATE words SET example_en_2 = 'She explored her identity through conversations with older family members.', example_ko_2 = '그녀는 나이 든 가족 구성원들과의 대화를 통해 정체성을 탐구했어요.', example_en_3 = 'Cultural identity is often passed down through family stories and traditions.', example_ko_3 = '문화적 정체성은 종종 가족 이야기와 전통을 통해 이어져요.', example_en_4 = 'Finding your identity as an individual within a family takes time.', example_ko_4 = '가족 안에서 개인으로서의 정체성을 찾는 데는 시간이 걸려요.', example_en_5 = 'She felt her identity was shaped as much by culture as by family.', example_ko_5 = '그녀는 자신의 정체성이 가족만큼이나 문화에 의해 형성됐다고 느꼈어요.' WHERE id = 'w_family_B1_26';
UPDATE words SET example_en_2 = 'Children who grow up loved tend to show greater resilience in adulthood.', example_ko_2 = '사랑받으며 자란 아이들은 성인기에 더 큰 회복력을 보이는 경향이 있어요.', example_en_3 = 'She showed great resilience after her parents'' divorce.', example_ko_3 = '그녀는 부모님의 이혼 후 큰 회복력을 보여줬어요.', example_en_4 = 'The family''s resilience helped them recover from the loss quickly.', example_ko_4 = '가족의 회복력이 그들이 상실에서 빠르게 회복하는 데 도움이 됐어요.', example_en_5 = 'Building resilience in children is one of the most valuable gifts a parent can give.', example_ko_5 = '아이들에게 회복력을 길러주는 것은 부모가 줄 수 있는 가장 소중한 선물 중 하나예요.' WHERE id = 'w_family_B1_27';
UPDATE words SET example_en_2 = 'Sibling rivalry is natural but needs to be managed with care.', example_ko_2 = '형제자매 간의 경쟁은 자연스럽지만 주의 깊게 관리해야 해요.', example_en_3 = 'She tried not to compare her children to reduce sibling rivalry.', example_ko_3 = '그녀는 형제자매 간의 경쟁을 줄이기 위해 자녀들을 비교하지 않으려 했어요.', example_en_4 = 'As adults, the sibling rivalry they once felt turned into a deep bond.', example_ko_4 = '성인이 되어 한때 느꼈던 형제자매 간의 경쟁이 깊은 유대로 바뀌었어요.', example_en_5 = 'Parents can ease sibling rivalry by giving each child individual attention.', example_ko_5 = '부모는 각 자녀에게 개별적인 관심을 주어 형제자매 간의 경쟁을 완화할 수 있어요.' WHERE id = 'w_family_B1_28';
UPDATE words SET example_en_2 = 'She felt a strong obligation to visit her parents every holiday.', example_ko_2 = '그녀는 매 명절에 부모님을 방문해야 할 강한 의무감을 느꼈어요.', example_en_3 = 'Family obligations can sometimes conflict with personal goals.', example_ko_3 = '가족의 의무는 때때로 개인 목표와 충돌할 수 있어요.', example_en_4 = 'He felt obligated to stay close and support his aging parents.', example_ko_4 = '그는 연로하신 부모님 가까이 있으며 지지해야 할 의무감을 느꼈어요.', example_en_5 = 'Understanding family obligation helps you make better choices together.', example_ko_5 = '가족의 의무를 이해하면 함께 더 나은 선택을 하는 데 도움이 돼요.' WHERE id = 'w_family_B1_29';
UPDATE words SET example_en_2 = 'He is grateful for the stable and loving home he grew up in.', example_ko_2 = '그는 자신이 자란 안정적이고 사랑이 넘치는 가정에 감사해요.', example_en_3 = 'She wrote a letter to her parents to express how grateful she was.', example_ko_3 = '그녀는 얼마나 감사한지 표현하기 위해 부모님께 편지를 썼어요.', example_en_4 = 'Being grateful for what your family does for you strengthens relationships.', example_ko_4 = '가족이 해준 것에 감사하는 것이 관계를 강화해요.', example_en_5 = 'She felt deeply grateful when her family supported her during illness.', example_ko_5 = '아플 때 가족이 지지해줘서 그녀는 깊이 감사했어요.' WHERE id = 'w_family_B1_30';
UPDATE words SET example_en_2 = 'The whole family shared in the grief of losing their grandfather.', example_ko_2 = '온 가족이 할아버지를 잃은 슬픔을 함께 나눴어요.', example_en_3 = 'She hid her grief to appear strong for her children.', example_ko_3 = '그녀는 자녀들에게 강한 모습을 보이기 위해 슬픔을 숨겼어요.', example_en_4 = 'Grief after losing a loved one can take many different forms.', example_ko_4 = '사랑하는 사람을 잃은 후의 슬픔은 다양한 형태를 취할 수 있어요.', example_en_5 = 'Being together as a family can ease the burden of grief.', example_ko_5 = '가족이 함께하는 것이 슬픔의 짐을 가볍게 할 수 있어요.' WHERE id = 'w_family_B1_31';
UPDATE words SET example_en_2 = 'She turned to her older brother for advice about her career.', example_ko_2 = '그녀는 커리어에 대한 조언을 얻으려고 오빠에게 갔어요.', example_en_3 = 'Good advice from a parent can save you a lot of trouble.', example_ko_3 = '부모님의 좋은 조언은 많은 어려움을 덜어줄 수 있어요.', example_en_4 = 'He gave his son practical advice about handling money wisely.', example_ko_4 = '그는 아들에게 돈을 현명하게 다루는 방법에 대한 실용적인 조언을 해줬어요.', example_en_5 = 'The best advice she ever received came from her grandmother.', example_ko_5 = '그녀가 받은 가장 좋은 조언은 할머니에게서 온 것이었어요.' WHERE id = 'w_family_B1_32';
UPDATE words SET example_en_2 = 'She considers her older sister her greatest role model.', example_ko_2 = '그녀는 언니를 자신의 가장 큰 역할 모델로 생각해요.', example_en_3 = 'Good parents are the first and most important role models for children.', example_ko_3 = '좋은 부모는 자녀에게 첫 번째이자 가장 중요한 역할 모델이에요.', example_en_4 = 'He became a role model for his younger cousins without even trying.', example_ko_4 = '그는 의식하지 않았지만 어린 사촌들에게 역할 모델이 됐어요.', example_en_5 = 'A strong role model within the family shapes a child''s character.', example_ko_5 = '가족 내의 강한 역할 모델이 아이의 성격을 형성해요.' WHERE id = 'w_family_B1_33';
UPDATE words SET example_en_2 = 'She teaches her children empathy by talking about others'' feelings.', example_ko_2 = '그녀는 다른 사람의 감정에 대해 이야기하며 자녀들에게 공감 능력을 가르쳐요.', example_en_3 = 'Empathy is one of the greatest gifts a parent can model for a child.', example_ko_3 = '공감 능력은 부모가 자녀에게 모범을 보일 수 있는 가장 큰 선물 중 하나예요.', example_en_4 = 'He showed empathy for his sister during her difficult breakup.', example_ko_4 = '그는 힘든 이별을 겪는 여동생에게 공감을 보여줬어요.', example_en_5 = 'Practising empathy within the family makes all relationships stronger.', example_ko_5 = '가족 내에서 공감 능력을 실천하면 모든 관계가 더 강해져요.' WHERE id = 'w_family_B1_34';
UPDATE words SET example_en_2 = 'She became the primary caregiver for her mother after the diagnosis.', example_ko_2 = '그녀는 진단 후 어머니의 주요 돌봄 제공자가 됐어요.', example_en_3 = 'Being a caregiver is one of the most demanding roles in a family.', example_ko_3 = '돌봄 제공자가 되는 것은 가족 내에서 가장 힘든 역할 중 하나예요.', example_en_4 = 'He took turns with his siblings as caregiver for their ageing father.', example_ko_4 = '그는 형제자매들과 번갈아가며 연로하신 아버지의 돌봄 제공자 역할을 했어요.', example_en_5 = 'Caregivers also need support and rest to maintain their own wellbeing.', example_ko_5 = '돌봄 제공자도 자신의 안녕을 유지하기 위해 지지와 휴식이 필요해요.' WHERE id = 'w_family_B1_35';

-- B2
UPDATE words SET example_en_2 = 'Intergenerational storytelling keeps family history alive for younger members.', example_ko_2 = '세대 간 이야기 나누기는 어린 구성원들을 위해 가족 역사를 살아있게 해요.', example_en_3 = 'The project brought together intergenerational volunteers to work side by side.', example_ko_3 = '그 프로젝트는 세대 간 자원봉사자들이 나란히 일하도록 모았어요.', example_en_4 = 'Intergenerational trauma is increasingly recognised by mental health professionals.', example_ko_4 = '세대 간 트라우마는 정신 건강 전문가들에게 점점 더 인정받고 있어요.', example_en_5 = 'She organised an intergenerational dinner to connect grandparents and grandchildren.', example_ko_5 = '그녀는 조부모님과 손자녀들을 연결하기 위해 세대 간 저녁 식사를 주최했어요.' WHERE id = 'w_family_B2_01';
UPDATE words SET example_en_2 = 'The power dynamic between parents and children shifts as children age.', example_ko_2 = '자녀가 성장함에 따라 부모와 자녀 사이의 역학 관계가 변해요.', example_en_3 = 'Unhealthy dynamics within a family often repeat across generations.', example_ko_3 = '가족 내의 건강하지 않은 역학 관계는 종종 세대에 걸쳐 반복돼요.', example_en_4 = 'They worked with a therapist to understand their family''s dynamics.', example_ko_4 = '그들은 치료사와 함께 가족의 역학 관계를 이해하기 위해 노력했어요.', example_en_5 = 'Changing the dynamic at home requires patience and commitment from everyone.', example_ko_5 = '가정 내의 역학 관계를 바꾸는 것은 모든 구성원의 인내심과 헌신이 필요해요.' WHERE id = 'w_family_B2_02';
UPDATE words SET example_en_2 = 'Therapists use the term dysfunctional to describe harmful family patterns.', example_ko_2 = '치료사들은 해로운 가족 패턴을 묘사하기 위해 역기능적이라는 용어를 사용해요.', example_en_3 = 'She grew up in a dysfunctional home and worked hard to break the cycle.', example_ko_3 = '그녀는 역기능적 가정에서 자랐고 그 순환을 끊기 위해 열심히 노력했어요.', example_en_4 = 'Even dysfunctional families can find healing with the right support.', example_ko_4 = '역기능적 가족도 올바른 지원을 받으면 치유를 찾을 수 있어요.', example_en_5 = 'Recognising dysfunctional patterns is a difficult but necessary first step.', example_ko_5 = '역기능적 패턴을 인식하는 것은 어렵지만 필요한 첫 번째 단계예요.' WHERE id = 'w_family_B2_03';
UPDATE words SET example_en_2 = 'The estrangement from her family lasted almost a decade.', example_ko_2 = '가족과의 관계 단절이 거의 10년 동안 지속됐어요.', example_en_3 = 'Estrangement from a parent is one of the most painful family experiences.', example_ko_3 = '부모와의 관계 단절은 가장 고통스러운 가족 경험 중 하나예요.', example_en_4 = 'She never spoke publicly about the estrangement from her siblings.', example_ko_4 = '그녀는 형제자매들과의 관계 단절에 대해 공개적으로 말하지 않았어요.', example_en_5 = 'Healing from estrangement takes time, honesty, and willingness from both sides.', example_ko_5 = '관계 단절로부터의 치유는 양쪽의 시간, 솔직함, 의지가 필요해요.' WHERE id = 'w_family_B2_04';
UPDATE words SET example_en_2 = 'Reconciliation after a long estrangement requires courage and humility.', example_ko_2 = '오랜 관계 단절 후의 화해는 용기와 겸손이 필요해요.', example_en_3 = 'She took the first step toward reconciliation by sending a letter.', example_ko_3 = '그녀는 편지를 보내 화해를 향한 첫걸음을 내디뎠어요.', example_en_4 = 'True reconciliation between family members goes deeper than just saying sorry.', example_ko_4 = '가족 간의 진정한 화해는 단순히 미안하다고 말하는 것보다 더 깊어요.', example_en_5 = 'Their reconciliation brought the whole family back together after years apart.', example_ko_5 = '그들의 화해는 수년 만에 온 가족을 다시 하나로 모아줬어요.' WHERE id = 'w_family_B2_05';
UPDATE words SET example_en_2 = 'She encouraged her children''s autonomy by letting them make small decisions.', example_ko_2 = '그녀는 자녀들이 작은 결정을 스스로 내리게 함으로써 자율성을 키워줬어요.', example_en_3 = 'Autonomy within a relationship does not mean distance or disconnection.', example_ko_3 = '관계 내의 자율성이 거리나 단절을 의미하지는 않아요.', example_en_4 = 'Teenagers need increasing autonomy as they approach adulthood.', example_ko_4 = '십대 청소년은 성인기에 가까워질수록 점점 더 많은 자율성이 필요해요.', example_en_5 = 'Respecting autonomy within a family creates a healthier dynamic.', example_ko_5 = '가족 내에서 자율성을 존중하면 더 건강한 역학 관계가 만들어져요.' WHERE id = 'w_family_B2_06';
UPDATE words SET example_en_2 = 'Research shows that authoritative parenting style leads to better outcomes for children.', example_ko_2 = '연구에 따르면 권위 있는 양육 방식이 아이들에게 더 나은 결과를 가져와요.', example_en_3 = 'Her relaxed parenting style suited her easy-going children well.', example_ko_3 = '그녀의 여유로운 양육 방식은 느긋한 자녀들에게 잘 맞았어요.', example_en_4 = 'Every family develops a parenting style that reflects their values.', example_ko_4 = '모든 가족은 자신들의 가치관을 반영하는 양육 방식을 발전시켜요.', example_en_5 = 'A consistent parenting style gives children a sense of stability.', example_ko_5 = '일관된 양육 방식은 아이들에게 안정감을 줘요.' WHERE id = 'w_family_B2_07';
UPDATE words SET example_en_2 = 'The therapist helped them recognise patterns of codependency in their relationship.', example_ko_2 = '치료사는 그들이 관계 속의 공동의존 패턴을 인식하도록 도와줬어요.', example_en_3 = 'Codependency often develops when one family member has a serious illness.', example_ko_3 = '공동의존은 종종 가족 구성원 중 한 명이 심각한 질병을 가질 때 발생해요.', example_en_4 = 'Breaking free from codependency requires support from a professional.', example_ko_4 = '공동의존에서 벗어나는 데는 전문가의 지원이 필요해요.', example_en_5 = 'She realised the codependency in her relationship was affecting her mental health.', example_ko_5 = '그녀는 관계 속의 공동의존이 정신 건강에 영향을 미치고 있다는 것을 깨달았어요.' WHERE id = 'w_family_B2_08';
UPDATE words SET example_en_2 = 'He took time off work to support his wife during her bereavement.', example_ko_2 = '그는 아내의 사별 기간을 지지하기 위해 일을 쉬었어요.', example_en_3 = 'Children often experience bereavement differently from adults.', example_ko_3 = '아이들은 종종 성인과 다르게 사별을 경험해요.', example_en_4 = 'Bereavement counseling helped the family process their grief together.', example_ko_4 = '사별 상담은 가족이 슬픔을 함께 처리하는 데 도움이 됐어요.', example_en_5 = 'Every person experiences bereavement in their own unique way.', example_ko_5 = '모든 사람은 자신만의 방식으로 사별을 경험해요.' WHERE id = 'w_family_B2_09';
UPDATE words SET example_en_2 = 'The family home was her grandmother''s greatest legacy to all of them.', example_ko_2 = '가족 집은 할머니가 그들 모두에게 남긴 가장 큰 유산이었어요.', example_en_3 = 'He wanted his legacy to be one of kindness and generosity.', example_ko_3 = '그는 자신의 유산이 친절함과 너그러움으로 기억되기를 원했어요.', example_en_4 = 'She worked hard to build a legacy that her children could be proud of.', example_ko_4 = '그녀는 자녀들이 자랑스러워할 유산을 만들기 위해 열심히 노력했어요.', example_en_5 = 'The values she passed on to her children are her most enduring legacy.', example_ko_5 = '그녀가 자녀들에게 전해준 가치관이 그녀의 가장 지속적인 유산이에요.' WHERE id = 'w_family_B2_10';
UPDATE words SET example_en_2 = 'She gave her children unconditional support during their struggles.', example_ko_2 = '그녀는 자녀들이 힘들어할 때 무조건적인 지지를 해줬어요.', example_en_3 = 'Unconditional acceptance within a family creates a safe emotional space.', example_ko_3 = '가족 내의 무조건적인 수용은 안전한 정서적 공간을 만들어요.', example_en_4 = 'He loved his children unconditionally, no matter what choices they made.', example_ko_4 = '그는 자녀들이 어떤 선택을 하든 무조건적으로 사랑했어요.', example_en_5 = 'Unconditional love does not mean having no expectations at all.', example_ko_5 = '무조건적인 사랑이 아무런 기대가 없다는 것을 의미하지는 않아요.' WHERE id = 'w_family_B2_11';
UPDATE words SET example_en_2 = 'Children in a blended family sometimes need extra time to adjust.', example_ko_2 = '혼합 가족의 아이들은 때때로 적응하기 위해 추가적인 시간이 필요해요.', example_en_3 = 'She worked hard to build strong bonds within their blended family.', example_ko_3 = '그녀는 혼합 가족 내에서 강한 유대를 만들기 위해 열심히 노력했어요.', example_en_4 = 'A blended family can be just as loving and functional as any other.', example_ko_4 = '혼합 가족도 다른 가족만큼 사랑스럽고 기능적일 수 있어요.', example_en_5 = 'The children from the blended family became very close over the years.', example_ko_5 = '혼합 가족의 아이들은 수년에 걸쳐 매우 가까워졌어요.' WHERE id = 'w_family_B2_12';
UPDATE words SET example_en_2 = 'She trained to become a foster care provider after her own children grew up.', example_ko_2 = '그녀는 자신의 아이들이 다 자란 후에 위탁 양육 제공자가 되기 위해 교육을 받았어요.', example_en_3 = 'Children in foster care need stability and long-term support.', example_ko_3 = '위탁 보호 중인 아이들에게는 안정성과 장기적인 지원이 필요해요.', example_en_4 = 'The foster care system aims to give vulnerable children a safe home.', example_ko_4 = '위탁 양육 제도는 취약한 아이들에게 안전한 집을 제공하는 것을 목표로 해요.', example_en_5 = 'He was placed in foster care at age seven after his mother became ill.', example_ko_5 = '그는 어머니가 아프게 된 후 일곱 살에 위탁 보호를 받았어요.' WHERE id = 'w_family_B2_13';
UPDATE words SET example_en_2 = 'The judge awarded guardianship to the grandmother after reviewing the case.', example_ko_2 = '판사는 사건을 검토한 후 할머니에게 후견인 자격을 부여했어요.', example_en_3 = 'She took on guardianship of her niece when her sister became unable to care for her.', example_ko_3 = '언니가 돌볼 수 없게 되자 그녀는 조카의 후견인이 됐어요.', example_en_4 = 'Legal guardianship gives an adult the rights of a parent.', example_ko_4 = '법적 후견인 자격은 성인에게 부모의 권리를 부여해요.', example_en_5 = 'Applying for guardianship requires working closely with legal professionals.', example_ko_5 = '후견인 자격을 신청하려면 법률 전문가와 긴밀하게 협력해야 해요.' WHERE id = 'w_family_B2_14';
UPDATE words SET example_en_2 = 'She found family counseling helpful in improving communication at home.', example_ko_2 = '그녀는 가족 상담이 가정 내 소통을 개선하는 데 도움이 된다고 생각했어요.', example_en_3 = 'Many families benefit from counseling even when there is no serious problem.', example_ko_3 = '심각한 문제가 없어도 많은 가족이 상담으로 도움을 받아요.', example_en_4 = 'Counseling helped them understand each other''s needs much better.', example_ko_4 = '상담은 그들이 서로의 필요를 훨씬 더 잘 이해하도록 도와줬어요.', example_en_5 = 'There is no shame in seeking counseling to strengthen your family.', example_ko_5 = '가족을 강화하기 위해 상담을 받는 것은 부끄러운 일이 아니에요.' WHERE id = 'w_family_B2_15';
UPDATE words SET example_en_2 = 'They agreed to try mediation before taking the custody dispute to court.', example_ko_2 = '그들은 양육권 분쟁을 법원에 가져가기 전에 중재를 시도해보기로 합의했어요.', example_en_3 = 'A skilled mediator helped the two brothers reach a fair agreement.', example_ko_3 = '능숙한 중재자가 두 형제가 공정한 합의에 도달하도록 도와줬어요.', example_en_4 = 'Mediation is often faster and less painful than going to court.', example_ko_4 = '중재는 법원에 가는 것보다 종종 더 빠르고 덜 고통스러워요.', example_en_5 = 'She trained as a family mediator to help others resolve disputes.', example_ko_5 = '그녀는 다른 사람들이 분쟁을 해결하도록 돕기 위해 가족 중재인으로 교육받았어요.' WHERE id = 'w_family_B2_16';
UPDATE words SET example_en_2 = 'The adjustment to having a new baby was harder than they expected.', example_ko_2 = '새 아기를 맞이하는 적응은 그들이 예상했던 것보다 더 어려웠어요.', example_en_3 = 'She needed time to make the adjustment to living alone after divorce.', example_ko_3 = '이혼 후 혼자 사는 것에 적응하기 위한 시간이 그녀에게 필요했어요.', example_en_4 = 'Moving to a new country requires a major adjustment for the whole family.', example_ko_4 = '새 나라로 이사하는 것은 온 가족에게 큰 적응을 요구해요.', example_en_5 = 'Children often find adjustment to new family structures easier than adults.', example_ko_5 = '아이들은 종종 성인보다 새로운 가족 구조에 적응하는 것이 더 쉽다고 느껴요.' WHERE id = 'w_family_B2_17';
UPDATE words SET example_en_2 = 'Her parents'' high expectations pushed her to work very hard.', example_ko_2 = '부모님의 높은 기대가 그녀를 매우 열심히 일하게 만들었어요.', example_en_3 = 'It is important to set realistic expectations within a family.', example_ko_3 = '가족 내에서 현실적인 기대를 설정하는 것이 중요해요.', example_en_4 = 'She learned to separate her own goals from her parents'' expectations.', example_ko_4 = '그녀는 자신의 목표를 부모님의 기대와 분리하는 법을 배웠어요.', example_en_5 = 'Managing expectations helps prevent disappointment in family relationships.', example_ko_5 = '기대를 관리하면 가족 관계에서 실망을 예방하는 데 도움이 돼요.' WHERE id = 'w_family_B2_18';
UPDATE words SET example_en_2 = 'She was raised with a strong sense of filial duty toward her parents.', example_ko_2 = '그녀는 부모님에 대한 강한 효도의 의무감을 가지고 자랐어요.', example_en_3 = 'Filial bonds are celebrated and reinforced during traditional festivals.', example_ko_3 = '효도의 유대는 전통 축제 기간에 기념되고 강화돼요.', example_en_4 = 'She felt a filial obligation to move closer to care for her aging mother.', example_ko_4 = '그녀는 연로하신 어머니를 돌보기 위해 더 가까이 이사해야 할 효도적 의무를 느꼈어요.', example_en_5 = 'Balancing filial responsibilities with personal ambitions is a common challenge.', example_ko_5 = '효도의 책임과 개인적 야망의 균형을 맞추는 것은 흔한 도전이에요.' WHERE id = 'w_family_B2_19';
UPDATE words SET example_en_2 = 'Cohabitation gave them a chance to learn each other''s habits.', example_ko_2 = '동거는 그들이 서로의 습관을 알아가는 기회를 줬어요.', example_en_3 = 'They chose cohabitation before marriage to ensure they were compatible.', example_ko_3 = '그들은 서로 잘 맞는지 확인하기 위해 결혼 전에 동거를 선택했어요.', example_en_4 = 'Cohabitation without marriage is more accepted now than in the past.', example_ko_4 = '결혼 없는 동거는 이제 과거보다 더 인정받고 있어요.', example_en_5 = 'Couples who practise cohabitation often face questions from older family members.', example_ko_5 = '동거를 실천하는 커플은 종종 나이 든 가족 구성원들로부터 질문을 받아요.' WHERE id = 'w_family_B2_20';
UPDATE words SET example_en_2 = 'She practised self-reliance by handling her finances independently from age eighteen.', example_ko_2 = '그녀는 열여덟 살부터 독립적으로 재정을 관리하며 자립심을 실천했어요.', example_en_3 = 'Teaching self-reliance to children builds their confidence and capability.', example_ko_3 = '아이들에게 자립심을 가르치면 그들의 자신감과 능력이 키워져요.', example_en_4 = 'She developed strong self-reliance during her years living abroad.', example_ko_4 = '그녀는 해외에서 생활하는 동안 강한 자립심을 키웠어요.', example_en_5 = 'Self-reliance and family support are not mutually exclusive.', example_ko_5 = '자립심과 가족의 지지는 서로 양립할 수 없는 것이 아니에요.' WHERE id = 'w_family_B2_21';
UPDATE words SET example_en_2 = 'Allowing vulnerability within a family creates deeper emotional connections.', example_ko_2 = '가족 내에서 취약성을 허용하면 더 깊은 감정적 연결이 만들어져요.', example_en_3 = 'She was afraid to show vulnerability even with her closest family members.', example_ko_3 = '그녀는 가장 가까운 가족 구성원들에게도 취약한 면을 보이는 것이 두려웠어요.', example_en_4 = 'Admitting vulnerability is often the first step toward healing.', example_ko_4 = '취약성을 인정하는 것이 종종 치유를 향한 첫 번째 단계예요.', example_en_5 = 'Children are naturally vulnerable and depend on their caregivers for safety.', example_ko_5 = '아이들은 본래 취약하고 안전을 위해 돌봄 제공자에게 의존해요.' WHERE id = 'w_family_B2_22';
UPDATE words SET example_en_2 = 'She valued authenticity and always spoke honestly with her family.', example_ko_2 = '그녀는 진정성을 소중히 여겼고 가족에게 항상 솔직하게 말했어요.', example_en_3 = 'Authenticity in a relationship means being honest even when it is hard.', example_ko_3 = '관계에서의 진정성은 어려울 때도 솔직하게 말하는 것을 의미해요.', example_en_4 = 'Children benefit from seeing authenticity modelled by their parents.', example_ko_4 = '아이들은 부모가 진정성을 모범으로 보여주는 것을 볼 때 도움을 받아요.', example_en_5 = 'His authenticity made him someone the whole family trusted deeply.', example_ko_5 = '그의 진정성은 그를 온 가족이 깊이 신뢰하는 사람으로 만들었어요.' WHERE id = 'w_family_B2_23';
UPDATE words SET example_en_2 = 'Childhood trauma can have long-lasting effects on adult relationships.', example_ko_2 = '어린 시절의 트라우마는 성인 관계에 오래 지속되는 영향을 미칠 수 있어요.', example_en_3 = 'She sought therapy to process the trauma she experienced growing up.', example_ko_3 = '그녀는 성장하면서 경험한 트라우마를 처리하기 위해 치료를 받기 시작했어요.', example_en_4 = 'Understanding trauma within the family can lead to greater compassion.', example_ko_4 = '가족 내 트라우마를 이해하면 더 큰 공감으로 이어질 수 있어요.', example_en_5 = 'Healing from trauma is possible with the right therapeutic support.', example_ko_5 = '올바른 치료적 지원이 있으면 트라우마로부터의 치유가 가능해요.' WHERE id = 'w_family_B2_24';
UPDATE words SET example_en_2 = 'She held herself accountable for the pain she caused her family.', example_ko_2 = '그녀는 가족에게 준 고통에 대해 스스로 책임을 졌어요.', example_en_3 = 'Accountability in a relationship means owning your mistakes openly.', example_ko_3 = '관계에서의 책임감은 실수를 공개적으로 인정하는 것을 의미해요.', example_en_4 = 'Parents who model accountability teach their children to do the same.', example_ko_4 = '책임감의 모범을 보이는 부모는 자녀들도 같은 행동을 하도록 가르쳐요.', example_en_5 = 'Accountability is a key part of rebuilding trust after a family conflict.', example_ko_5 = '책임감은 가족 갈등 이후 신뢰를 회복하는 핵심 요소예요.' WHERE id = 'w_family_B2_25';
UPDATE words SET example_en_2 = 'She felt understood for the first time when her mother offered real validation.', example_ko_2 = '어머니가 진정한 인정을 제공했을 때 그녀는 처음으로 이해받는다고 느꼈어요.', example_en_3 = 'Validation of a child''s feelings builds emotional intelligence over time.', example_ko_3 = '아이의 감정을 인정하면 시간이 지나면서 감성 지능이 키워져요.', example_en_4 = 'She struggled with the absence of validation from her father growing up.', example_ko_4 = '그녀는 성장하면서 아버지의 인정 부재로 어려움을 겪었어요.', example_en_5 = 'Validation does not mean agreeing — it means acknowledging feelings.', example_ko_5 = '인정은 동의를 의미하는 것이 아니라 감정을 인식하는 것을 의미해요.' WHERE id = 'w_family_B2_26';
UPDATE words SET example_en_2 = 'She carried years of resentment toward her father before seeking therapy.', example_ko_2 = '그녀는 치료를 받기 전까지 수년 동안 아버지에 대한 억울함을 품고 있었어요.', example_en_3 = 'Resentment that builds up silently often damages family relationships.', example_ko_3 = '말없이 쌓인 억울함은 종종 가족 관계를 해쳐요.', example_en_4 = 'Talking openly can prevent resentment from taking root within a family.', example_ko_4 = '솔직하게 이야기하면 억울함이 가족 내에서 뿌리내리는 것을 예방할 수 있어요.', example_en_5 = 'He did not realise how much resentment he had built up until he spoke about it.', example_ko_5 = '그는 이야기하기 전까지 얼마나 많은 억울함이 쌓였는지 깨닫지 못했어요.' WHERE id = 'w_family_B2_27';
UPDATE words SET example_en_2 = 'She chose forgiveness not for them but for her own peace of mind.', example_ko_2 = '그녀는 상대방을 위해서가 아니라 자신의 마음의 평화를 위해 용서를 선택했어요.', example_en_3 = 'Forgiveness within a family takes time and does not happen overnight.', example_ko_3 = '가족 내의 용서는 시간이 걸리며 하룻밤에 일어나지 않아요.', example_en_4 = 'He offered forgiveness to his estranged father after many years.', example_ko_4 = '그는 수년 만에 소원해진 아버지에게 용서를 건넸어요.', example_en_5 = 'Forgiveness is a gift you give yourself as much as the other person.', example_ko_5 = '용서는 상대방만큼이나 자신에게도 주는 선물이에요.' WHERE id = 'w_family_B2_28';
UPDATE words SET example_en_2 = 'His dependency on his parents continued well into his thirties.', example_ko_2 = '그의 부모님에 대한 의존은 30대까지 계속됐어요.', example_en_3 = 'Emotional dependency in a family can become suffocating over time.', example_ko_3 = '가족 내의 감정적 의존은 시간이 지나면서 숨막힐 수 있어요.', example_en_4 = 'Addressing unhealthy dependency requires honesty from both parties.', example_ko_4 = '건강하지 않은 의존을 해결하려면 양측의 솔직함이 필요해요.', example_en_5 = 'She recognised that her dependency was holding both her and her mother back.', example_ko_5 = '그녀는 자신의 의존이 자신과 어머니 모두를 발목 잡고 있다는 것을 인식했어요.' WHERE id = 'w_family_B2_29';
UPDATE words SET example_en_2 = 'He called his parents every week to maintain the emotional support between them.', example_ko_2 = '그는 그들 사이의 정서적 지지를 유지하기 위해 매주 부모님께 전화했어요.', example_en_3 = 'Emotional support from a sibling is irreplaceable during difficult times.', example_ko_3 = '힘든 시간에 형제자매의 정서적 지지는 대체할 수 없어요.', example_en_4 = 'She made sure her children always felt her emotional support.', example_ko_4 = '그녀는 자녀들이 항상 자신의 정서적 지지를 느끼도록 했어요.', example_en_5 = 'Providing emotional support does not mean fixing every problem.', example_ko_5 = '정서적 지지를 제공하는 것이 모든 문제를 해결하는 것을 의미하지는 않아요.' WHERE id = 'w_family_B2_30';
UPDATE words SET example_en_2 = 'She realised that her family environment had been quietly toxic for years.', example_ko_2 = '그녀는 자신의 가족 환경이 수년간 조용히 독성적이었다는 것을 깨달았어요.', example_en_3 = 'Toxic communication patterns are often passed down without awareness.', example_ko_3 = '독성적 소통 패턴은 종종 인식 없이 이어져요.', example_en_4 = 'She set limits with a toxic family member to protect her wellbeing.', example_ko_4 = '그녀는 자신의 안녕을 보호하기 위해 독성적인 가족 구성원과 한계를 설정했어요.', example_en_5 = 'Recognising toxic patterns is the first step to creating change.', example_ko_5 = '독성적 패턴을 인식하는 것이 변화를 만들기 위한 첫 번째 단계예요.' WHERE id = 'w_family_B2_31';
UPDATE words SET example_en_2 = 'The enmeshment between mother and daughter made healthy independence impossible.', example_ko_2 = '어머니와 딸 사이의 과도한 융합이 건강한 독립을 불가능하게 만들었어요.', example_en_3 = 'She worked with a therapist to untangle herself from family enmeshment.', example_ko_3 = '그녀는 치료사와 함께 가족 간의 과도한 융합에서 벗어나기 위해 노력했어요.', example_en_4 = 'Enmeshment looks like closeness but actually prevents individual growth.', example_ko_4 = '과도한 융합은 친밀해 보이지만 사실 개인의 성장을 막아요.', example_en_5 = 'Recognising enmeshment in a family is the first step toward healthier boundaries.', example_ko_5 = '가족 내의 과도한 융합을 인식하는 것이 더 건강한 경계를 향한 첫 번째 단계예요.' WHERE id = 'w_family_B2_32';
UPDATE words SET example_en_2 = 'Her differentiation from her parents was a gradual and necessary process.', example_ko_2 = '부모님으로부터의 자기 분화는 점진적이고 필요한 과정이었어요.', example_en_3 = 'Healthy differentiation allows people to stay connected while remaining individuals.', example_ko_3 = '건강한 자기 분화는 사람들이 개인으로 남으면서 연결을 유지하게 해요.', example_en_4 = 'She achieved differentiation from her family by developing her own values.', example_ko_4 = '그녀는 자신만의 가치관을 발전시킴으로써 가족으로부터의 자기 분화를 이뤘어요.', example_en_5 = 'Differentiation is not about rejecting family but about developing selfhood.', example_ko_5 = '자기 분화는 가족을 거부하는 것이 아니라 자아를 발전시키는 것에 관한 거예요.' WHERE id = 'w_family_B2_33';
UPDATE words SET example_en_2 = 'She learned the importance of setting clear boundaries with her in-laws.', example_ko_2 = '그녀는 시댁 식구들과 명확한 경계를 설정하는 것의 중요성을 배웠어요.', example_en_3 = 'Healthy boundaries protect both individuals and the family as a whole.', example_ko_3 = '건강한 경계는 개인과 가족 전체 모두를 보호해요.', example_en_4 = 'He struggled to communicate his boundaries without feeling guilty.', example_ko_4 = '그는 죄책감 없이 자신의 경계를 표현하는 데 어려움을 겪었어요.', example_en_5 = 'Respecting each other''s boundaries is one of the foundations of trust.', example_ko_5 = '서로의 경계를 존중하는 것이 신뢰의 기반 중 하나예요.' WHERE id = 'w_family_B2_34';
UPDATE words SET example_en_2 = 'Her anxious attachment style made her overly dependent on her partner.', example_ko_2 = '그녀의 불안한 애착 유형이 파트너에게 과도하게 의존하게 만들었어요.', example_en_3 = 'Understanding your attachment style can improve all your relationships.', example_ko_3 = '자신의 애착 유형을 이해하면 모든 관계가 개선될 수 있어요.', example_en_4 = 'A secure attachment style typically develops when caregivers are consistent.', example_ko_4 = '안정적인 애착 유형은 주로 돌봄 제공자가 일관적일 때 발달해요.', example_en_5 = 'Therapy can help people shift from an insecure to a more secure attachment style.', example_ko_5 = '치료는 사람들이 불안정한 애착 유형에서 더 안정적인 유형으로 전환하도록 도울 수 있어요.' WHERE id = 'w_family_B2_35';

-- C1
UPDATE words SET example_en_2 = 'Filial piety shapes how children relate to their parents in many Asian cultures.', example_ko_2 = '효도는 많은 아시아 문화권에서 자녀들이 부모님과 관계를 맺는 방식을 형성해요.', example_en_3 = 'She was raised to understand filial piety as a core family value.', example_ko_3 = '그녀는 효도를 핵심 가족 가치로 이해하도록 키워졌어요.', example_en_4 = 'In some cultures, filial piety includes supporting parents financially in old age.', example_ko_4 = '일부 문화권에서 효도에는 노년기에 부모님을 재정적으로 지원하는 것이 포함돼요.', example_en_5 = 'She demonstrated filial piety by moving back home to care for her mother.', example_ko_5 = '그녀는 어머니를 돌보기 위해 집으로 돌아옴으로써 효도를 실천했어요.' WHERE id = 'w_family_C1_01';
UPDATE words SET example_en_2 = 'Kinship networks provide support, identity, and belonging across cultures.', example_ko_2 = '친족 네트워크는 문화 전반에 걸쳐 지지, 정체성, 소속감을 제공해요.', example_en_3 = 'The definition of kinship varies widely between different societies.', example_ko_3 = '친족 관계의 정의는 다양한 사회 사이에서 크게 달라요.', example_en_4 = 'She explored her sense of kinship through her grandmother''s stories.', example_ko_4 = '그녀는 할머니의 이야기를 통해 친족 관계에 대한 감각을 탐구했어요.', example_en_5 = 'Kinship obligations can create both support and pressure within families.', example_ko_5 = '친족 의무는 가족 내에서 지지와 압력을 모두 만들 수 있어요.' WHERE id = 'w_family_C1_02';
UPDATE words SET example_en_2 = 'Attachment theory helps explain why some adults fear abandonment.', example_ko_2 = '애착 이론은 일부 성인들이 왜 유기를 두려워하는지 설명하는 데 도움이 돼요.', example_en_3 = 'Bowlby developed attachment theory after studying children in hospitals.', example_ko_3 = '볼비는 병원에서 아이들을 연구한 후 애착 이론을 발전시켰어요.', example_en_4 = 'Understanding attachment theory changed how she parented her own children.', example_ko_4 = '애착 이론을 이해한 것이 그녀가 자녀를 양육하는 방식을 바꿨어요.', example_en_5 = 'Attachment theory has had a profound influence on modern family therapy.', example_ko_5 = '애착 이론은 현대 가족 치료에 깊은 영향을 미쳤어요.' WHERE id = 'w_family_C1_03';
UPDATE words SET example_en_2 = 'Research on intergenerational trauma has grown significantly in recent years.', example_ko_2 = '세대 간 트라우마 연구는 최근 몇 년간 크게 성장했어요.', example_en_3 = 'She realised that her anxiety might be linked to intergenerational trauma.', example_ko_3 = '그녀는 자신의 불안이 세대 간 트라우마와 연관될 수 있다는 것을 깨달았어요.', example_en_4 = 'Healing intergenerational trauma often requires both personal and family therapy.', example_ko_4 = '세대 간 트라우마 치유에는 종종 개인 치료와 가족 치료 모두가 필요해요.', example_en_5 = 'Breaking the cycle of intergenerational trauma starts with awareness and courage.', example_ko_5 = '세대 간 트라우마의 순환을 끊는 것은 인식과 용기에서 시작돼요.' WHERE id = 'w_family_C1_04';
UPDATE words SET example_en_2 = 'Socialization begins the moment a child is born into a family.', example_ko_2 = '사회화는 아이가 가족에 태어나는 순간 시작돼요.', example_en_3 = 'Schools and peer groups support socialization beyond the family unit.', example_ko_3 = '학교와 또래 집단은 가족 단위를 넘어 사회화를 지원해요.', example_en_4 = 'She studied how immigration affects the socialization of children.', example_ko_4 = '그녀는 이민이 아이들의 사회화에 어떻게 영향을 미치는지 연구했어요.', example_en_5 = 'Gender roles are one aspect of socialization that begins at home.', example_ko_5 = '성 역할은 가정에서 시작되는 사회화의 한 측면이에요.' WHERE id = 'w_family_C1_05';
UPDATE words SET example_en_2 = 'The formative years of childhood are deeply shaped by family experiences.', example_ko_2 = '어린 시절의 형성기는 가족 경험에 의해 깊이 형성돼요.', example_en_3 = 'She credits her grandmother with being the most formative influence in her life.', example_ko_3 = '그녀는 할머니가 삶에서 가장 중요한 형성적 영향을 미쳤다고 인정해요.', example_en_4 = 'Formative experiences in early childhood shape the way adults think and feel.', example_ko_4 = '유아기의 형성적 경험은 어른들이 생각하고 느끼는 방식을 형성해요.', example_en_5 = 'A stable home environment creates the most positive formative conditions for children.', example_ko_5 = '안정적인 가정 환경이 아이들에게 가장 긍정적인 형성 조건을 만들어요.' WHERE id = 'w_family_C1_06';
UPDATE words SET example_en_2 = 'She became a surrogate mother to two children whose parents had passed away.', example_ko_2 = '그녀는 부모가 돌아가신 두 아이의 대리 어머니가 됐어요.', example_en_3 = 'A surrogate figure can provide important emotional support to a child in need.', example_ko_3 = '대리 인물은 도움이 필요한 아이에게 중요한 정서적 지지를 제공할 수 있어요.', example_en_4 = 'Teachers often serve as surrogate role models for children lacking parental guidance.', example_ko_4 = '교사들은 종종 부모의 지도가 부족한 아이들에게 대리 역할 모델이 돼요.', example_en_5 = 'He served as a surrogate father for his younger siblings after their parents'' divorce.', example_ko_5 = '그는 부모님의 이혼 후 어린 형제자매들에게 대리 아버지 역할을 했어요.' WHERE id = 'w_family_C1_07';
UPDATE words SET example_en_2 = 'She discovered fascinating connections while researching her genealogy.', example_ko_2 = '족보를 조사하면서 그녀는 흥미로운 연결고리를 발견했어요.', example_en_3 = 'Genealogy research has become much easier with online databases.', example_ko_3 = '족보 연구는 온라인 데이터베이스 덕분에 훨씬 쉬워졌어요.', example_en_4 = 'Understanding your genealogy can give you a deeper sense of identity.', example_ko_4 = '족보를 이해하면 더 깊은 정체성 감각을 가질 수 있어요.', example_en_5 = 'The family''s genealogy traced back to a small village in the south.', example_ko_5 = '그 가족의 족보는 남쪽의 작은 마을까지 거슬러 올라갔어요.' WHERE id = 'w_family_C1_08';
UPDATE words SET example_en_2 = 'The succession of the family business was planned carefully in advance.', example_ko_2 = '가족 사업의 계승은 사전에 신중하게 계획됐어요.', example_en_3 = 'She was the first daughter to challenge traditional succession rules.', example_ko_3 = '그녀는 전통적인 계승 규칙에 도전한 첫 번째 딸이었어요.', example_en_4 = 'Without a clear succession plan, family businesses often struggle after the founder retires.', example_ko_4 = '명확한 계승 계획 없이는 창업자가 은퇴한 후 가족 사업이 종종 어려움을 겪어요.', example_en_5 = 'Succession discussions can reveal hidden tensions within a family.', example_ko_5 = '계승 논의는 가족 내에 숨겨진 긴장을 드러낼 수 있어요.' WHERE id = 'w_family_C1_09';
UPDATE words SET example_en_2 = 'Laws on consanguinity differ between countries and religious traditions.', example_ko_2 = '혈연 관계에 관한 법률은 나라와 종교적 전통에 따라 달라요.', example_en_3 = 'Close consanguinity was once common in certain royal families.', example_ko_3 = '가까운 혈연 관계는 과거 특정 왕족 가문에서 흔했어요.', example_en_4 = 'She studied consanguinity rules in different legal systems for her thesis.', example_ko_4 = '그녀는 논문을 위해 다양한 법 체계에서의 혈연 관계 규정을 연구했어요.', example_en_5 = 'Degrees of consanguinity determine which family marriages are legally permitted.', example_ko_5 = '혈연 관계의 정도에 따라 법적으로 허용되는 가족 결혼이 결정돼요.' WHERE id = 'w_family_C1_10';
UPDATE words SET example_en_2 = 'In matrilineal societies, a child inherits identity from the mother''s side.', example_ko_2 = '모계 사회에서 아이는 어머니 쪽으로부터 정체성을 상속받아요.', example_en_3 = 'The Khasi people of India follow a matrilineal kinship system.', example_ko_3 = '인도의 카시족은 모계 친족 체계를 따라요.', example_en_4 = 'She researched matrilineal cultures for her anthropology dissertation.', example_ko_4 = '그녀는 인류학 논문을 위해 모계 문화를 연구했어요.', example_en_5 = 'Matrilineal descent does not necessarily mean the mother has more power.', example_ko_5 = '모계 혈통이 반드시 어머니가 더 많은 권력을 가진다는 것을 의미하지는 않아요.' WHERE id = 'w_family_C1_11';
UPDATE words SET example_en_2 = 'In a patrilineal system, the family name is passed through the father''s line.', example_ko_2 = '부계 체계에서 가문 이름은 아버지의 계통을 통해 이어져요.', example_en_3 = 'Many East Asian cultures follow patrilineal naming conventions.', example_ko_3 = '많은 동아시아 문화권은 부계 작명 관습을 따라요.', example_en_4 = 'The patrilineal system was dominant in most ancient civilisations.', example_ko_4 = '부계 체계는 대부분의 고대 문명에서 지배적이었어요.', example_en_5 = 'She challenged the patrilineal tradition by keeping her own family name after marriage.', example_ko_5 = '그녀는 결혼 후 자신의 성을 유지함으로써 부계 전통에 도전했어요.' WHERE id = 'w_family_C1_12';
UPDATE words SET example_en_2 = 'Parents often use milestones to assess whether their child is at the right developmental stage.', example_ko_2 = '부모는 종종 이정표를 사용하여 자녀가 올바른 발달 단계에 있는지 평가해요.', example_en_3 = 'The developmental stage of adolescence is marked by identity exploration.', example_ko_3 = '청소년기의 발달 단계는 정체성 탐구로 특징지어져요.', example_en_4 = 'Understanding each developmental stage helps parents respond appropriately.', example_ko_4 = '각 발달 단계를 이해하면 부모가 적절하게 반응하는 데 도움이 돼요.', example_en_5 = 'Each developmental stage brings new opportunities and challenges for both child and parent.', example_ko_5 = '각 발달 단계는 아이와 부모 모두에게 새로운 기회와 도전을 가져다줘요.' WHERE id = 'w_family_C1_13';
UPDATE words SET example_en_2 = 'Psychosocial development continues throughout a person''s entire lifespan.', example_ko_2 = '심리사회적 발달은 한 사람의 전 생애에 걸쳐 계속돼요.', example_en_3 = 'Erikson''s psychosocial theory focuses on the role of family in identity development.', example_ko_3 = '에릭슨의 심리사회적 이론은 정체성 발달에서 가족의 역할에 초점을 맞춰요.', example_en_4 = 'A child''s psychosocial wellbeing depends greatly on family stability.', example_ko_4 = '아이의 심리사회적 안녕은 가족 안정성에 크게 의존해요.', example_en_5 = 'She studied psychosocial development to better support at-risk children.', example_ko_5 = '그녀는 위기 아동을 더 잘 지원하기 위해 심리사회적 발달을 연구했어요.' WHERE id = 'w_family_C1_14';
UPDATE words SET example_en_2 = 'Close friends who function like siblings are a form of fictive kinship.', example_ko_2 = '형제자매처럼 기능하는 친한 친구들은 의사 친족의 한 형태예요.', example_en_3 = 'In many communities, fictive kinship bonds are just as strong as biological ones.', example_ko_3 = '많은 공동체에서 의사 친족 유대는 생물학적 유대만큼 강해요.', example_en_4 = 'She considered her mentor a fictive kinship figure — like an older sister.', example_ko_4 = '그녀는 멘토를 언니 같은 의사 친족으로 여겼어요.', example_en_5 = 'Fictive kinship reflects the human need to create family beyond biology.', example_ko_5 = '의사 친족은 생물학을 넘어 가족을 만들려는 인간의 욕구를 반영해요.' WHERE id = 'w_family_C1_15';
UPDATE words SET example_en_2 = 'She returned to her ancestral homeland to connect with her roots.', example_ko_2 = '그녀는 자신의 뿌리와 연결하기 위해 조상의 고향으로 돌아갔어요.', example_en_3 = 'The ancestral home had been in the family for over two hundred years.', example_ko_3 = '그 조상의 집은 200년 넘게 가족의 것이었어요.', example_en_4 = 'Learning ancestral languages helps preserve cultural identity.', example_ko_4 = '조상의 언어를 배우면 문화적 정체성을 보존하는 데 도움이 돼요.', example_en_5 = 'She felt a deep connection to her ancestral culture through family stories.', example_ko_5 = '그녀는 가족 이야기를 통해 조상의 문화에 깊은 연결을 느꼈어요.' WHERE id = 'w_family_C1_16';
UPDATE words SET example_en_2 = 'Her lineage on her father''s side traced back centuries.', example_ko_2 = '아버지 쪽 혈통은 수백 년 전까지 거슬러 올라갔어요.', example_en_3 = 'Knowing your lineage can give you a stronger sense of belonging.', example_ko_3 = '자신의 혈통을 아는 것은 더 강한 소속감을 줄 수 있어요.', example_en_4 = 'She was proud of her lineage and the values passed down within it.', example_ko_4 = '그녀는 자신의 혈통과 그 안에서 이어진 가치관을 자랑스러워했어요.', example_en_5 = 'The lineage of a family carries both history and responsibility.', example_ko_5 = '가족의 혈통은 역사와 책임 모두를 담고 있어요.' WHERE id = 'w_family_C1_17';
UPDATE words SET example_en_2 = 'Bringing a new baby home disrupts the existing household dynamics significantly.', example_ko_2 = '새 아기를 집으로 데려오면 기존의 가정 내 역학 관계가 크게 흔들려요.', example_en_3 = 'She worked with a counselor to understand the household dynamics she grew up in.', example_ko_3 = '그녀는 자신이 자란 가정 내 역학 관계를 이해하기 위해 상담사와 협력했어요.', example_en_4 = 'Household dynamics can shift dramatically after a parent loses their job.', example_ko_4 = '부모 중 한 명이 직장을 잃으면 가정 내 역학 관계가 크게 바뀔 수 있어요.', example_en_5 = 'Understanding household dynamics helps family members support each other better.', example_ko_5 = '가정 내 역학 관계를 이해하면 가족 구성원들이 서로를 더 잘 지지하는 데 도움이 돼요.' WHERE id = 'w_family_C1_18';
UPDATE words SET example_en_2 = 'Role differentiation within the family became less rigid in modern households.', example_ko_2 = '가족 내 역할 분화는 현대 가정에서 덜 경직되게 됐어요.', example_en_3 = 'She studied role differentiation in dual-income families for her research.', example_ko_3 = '그녀는 연구를 위해 맞벌이 가족에서의 역할 분화를 연구했어요.', example_en_4 = 'Clear role differentiation helps each family member understand their responsibilities.', example_ko_4 = '명확한 역할 분화는 각 가족 구성원이 자신의 책임을 이해하는 데 도움이 돼요.', example_en_5 = 'The role differentiation in her family was flexible and based on individual strengths.', example_ko_5 = '그녀의 가족 내 역할 분화는 유연하고 개인의 강점을 기반으로 했어요.' WHERE id = 'w_family_C1_19';
UPDATE words SET example_en_2 = 'She applied family systems theory to understand her parents'' relationship.', example_ko_2 = '그녀는 부모님의 관계를 이해하기 위해 가족 체계 이론을 적용했어요.', example_en_3 = 'Family systems theory sees each member as part of an interconnected whole.', example_ko_3 = '가족 체계 이론은 각 구성원을 상호 연결된 전체의 일부로 봐요.', example_en_4 = 'Therapists trained in family systems theory often work with the entire family.', example_ko_4 = '가족 체계 이론에서 훈련받은 치료사는 종종 가족 전체와 함께 작업해요.', example_en_5 = 'Family systems theory helps explain why individual problems are rarely just individual.', example_ko_5 = '가족 체계 이론은 개인적인 문제가 왜 단순히 개인의 문제만이 아닌지를 설명하는 데 도움이 돼요.' WHERE id = 'w_family_C1_20';
UPDATE words SET example_en_2 = 'The nature vs nurture debate has shaped child psychology for decades.', example_ko_2 = '천성 대 양육 논쟁은 수십 년 동안 아동 심리학을 형성해왔어요.', example_en_3 = 'She argued that nature vs nurture is a false dichotomy — both matter.', example_ko_3 = '그녀는 천성 대 양육이 잘못된 이분법이라고 주장했어요 — 둘 다 중요해요.', example_en_4 = 'Parents often wonder how much of their child''s personality is nature vs nurture.', example_ko_4 = '부모들은 종종 자녀의 성격이 얼마나 천성이고 얼마나 양육인지 궁금해해요.', example_en_5 = 'Twin studies have provided important insights into the nature vs nurture debate.', example_ko_5 = '쌍둥이 연구는 천성 대 양육 논쟁에 중요한 통찰을 제공해왔어요.' WHERE id = 'w_family_C1_21';
UPDATE words SET example_en_2 = 'Children of immigrants often experience acculturation more quickly than their parents.', example_ko_2 = '이민자의 자녀들은 종종 부모보다 더 빠르게 문화 적응을 경험해요.', example_en_3 = 'Acculturation can create tension between parents and children in immigrant families.', example_ko_3 = '문화 적응은 이민 가족에서 부모와 자녀 사이의 긴장을 유발할 수 있어요.', example_en_4 = 'She studied acculturation among second-generation Korean immigrants.', example_ko_4 = '그녀는 2세대 한국 이민자들의 문화 적응을 연구했어요.', example_en_5 = 'Acculturation does not mean forgetting your heritage — it means adapting to a new context.', example_ko_5 = '문화 적응은 유산을 잊는 것이 아니라 새로운 맥락에 적응하는 것을 의미해요.' WHERE id = 'w_family_C1_22';
UPDATE words SET example_en_2 = 'Cultural transmission happens through language, food, stories, and rituals.', example_ko_2 = '문화 전수는 언어, 음식, 이야기, 의식을 통해 이루어져요.', example_en_3 = 'She studied how cultural transmission changes when families move abroad.', example_ko_3 = '그녀는 가족이 해외로 이주할 때 문화 전수가 어떻게 변하는지 연구했어요.', example_en_4 = 'Cultural transmission within the family preserves knowledge across generations.', example_ko_4 = '가족 내의 문화 전수는 세대에 걸쳐 지식을 보존해요.', example_en_5 = 'Parents play the most direct role in the cultural transmission of values.', example_ko_5 = '부모는 가치관의 문화 전수에서 가장 직접적인 역할을 해요.' WHERE id = 'w_family_C1_23';
UPDATE words SET example_en_2 = 'Shared rituals and holidays reinforce a family''s collective identity.', example_ko_2 = '공유된 의식과 명절은 가족의 집단 정체성을 강화해요.', example_en_3 = 'A strong collective identity helps family members feel they belong.', example_ko_3 = '강한 집단 정체성은 가족 구성원들이 소속감을 느끼는 데 도움이 돼요.', example_en_4 = 'Cultural minority families often have a particularly strong collective identity.', example_ko_4 = '문화적 소수 가족은 종종 특히 강한 집단 정체성을 갖고 있어요.', example_en_5 = 'Her collective identity as part of a close-knit family gave her confidence.', example_ko_5 = '결속력 있는 가족의 일원으로서의 집단 정체성이 그녀에게 자신감을 줬어요.' WHERE id = 'w_family_C1_24';
UPDATE words SET example_en_2 = 'She tried to offer her children unconditional regard regardless of their choices.', example_ko_2 = '그녀는 자녀들의 선택에 상관없이 무조건적 존중을 제공하려 했어요.', example_en_3 = 'Carl Rogers believed unconditional regard was essential to human growth.', example_ko_3 = '칼 로저스는 무조건적 존중이 인간 성장에 필수적이라고 믿었어요.', example_en_4 = 'Parents who show unconditional regard raise children with healthier self-worth.', example_ko_4 = '무조건적 존중을 보이는 부모는 더 건강한 자존감을 가진 아이들을 키워요.', example_en_5 = 'Unconditional regard within a family creates safety and openness.', example_ko_5 = '가족 내의 무조건적 존중은 안전함과 개방성을 만들어요.' WHERE id = 'w_family_C1_25';
UPDATE words SET example_en_2 = 'She found her sense of generativity by mentoring young people in her community.', example_ko_2 = '그녀는 지역 사회의 젊은이들을 멘토링하면서 생성감을 발견했어요.', example_en_3 = 'Parents naturally experience generativity through raising and nurturing their children.', example_ko_3 = '부모는 자녀를 키우고 양육함으로써 자연스럽게 생성감을 경험해요.', example_en_4 = 'Grandparents often feel renewed generativity when grandchildren are born.', example_ko_4 = '조부모는 손자녀가 태어날 때 종종 생성감을 새롭게 느껴요.', example_en_5 = 'Generativity is one of the key motivations behind leaving a lasting family legacy.', example_ko_5 = '생성감은 지속적인 가족 유산을 남기려는 핵심 동기 중 하나예요.' WHERE id = 'w_family_C1_26';
UPDATE words SET example_en_2 = 'Family wellbeing is deeply relational — it depends on how members treat each other.', example_ko_2 = '가족의 안녕은 깊이 관계적이에요 — 구성원들이 서로를 어떻게 대하느냐에 달려 있어요.', example_en_3 = 'A relational approach to parenting focuses on connection before correction.', example_ko_3 = '양육에 대한 관계적 접근은 교정보다 연결을 먼저 중시해요.', example_en_4 = 'She brought a relational perspective to her family therapy training.', example_ko_4 = '그녀는 가족 치료 훈련에 관계적 관점을 가져왔어요.', example_en_5 = 'Relational skills learned in the family are applied throughout a person''s life.', example_ko_5 = '가족 내에서 배운 관계적 기술은 삶 전반에 걸쳐 적용돼요.' WHERE id = 'w_family_C1_27';
UPDATE words SET example_en_2 = 'Effective communication reduces the risk of interpersonal conflict at home.', example_ko_2 = '효과적인 소통은 가정에서 대인 갈등의 위험을 줄여요.', example_en_3 = 'Interpersonal conflict between parents affects children''s sense of security.', example_ko_3 = '부모 사이의 대인 갈등은 아이들의 안정감에 영향을 미쳐요.', example_en_4 = 'She learned to navigate interpersonal conflict without raising her voice.', example_ko_4 = '그녀는 목소리를 높이지 않고 대인 갈등을 헤쳐나가는 법을 배웠어요.', example_en_5 = 'Unresolved interpersonal conflict in a family tends to grow over time.', example_ko_5 = '가족 내에서 해결되지 않은 대인 갈등은 시간이 지나면서 커지는 경향이 있어요.' WHERE id = 'w_family_C1_28';
UPDATE words SET example_en_2 = 'Her affiliation with a close-knit extended family gave her strength.', example_ko_2 = '결속력 있는 대가족과의 소속감이 그녀에게 힘을 줬어요.', example_en_3 = 'A strong sense of affiliation within a family supports mental wellbeing.', example_ko_3 = '가족 내의 강한 소속감은 정신적 안녕을 지지해요.', example_en_4 = 'She felt a deep affiliation with her cultural heritage through her grandmother.', example_ko_4 = '그녀는 할머니를 통해 문화적 유산에 깊은 소속감을 느꼈어요.', example_en_5 = 'Affiliation with family builds a sense of continuity and roots.', example_ko_5 = '가족과의 소속감은 연속성과 뿌리 의식을 키워요.' WHERE id = 'w_family_C1_29';
UPDATE words SET example_en_2 = 'The whole clan gathered for a ceremonial meal to honour their ancestors.', example_ko_2 = '온 씨족이 조상을 기리기 위한 의식 식사에 모였어요.', example_en_3 = 'She traced her family''s history back to a powerful clan in the highlands.', example_ko_3 = '그녀는 가족의 역사를 고지대의 강력한 씨족까지 추적했어요.', example_en_4 = 'The clan met annually to renew their ties and share news.', example_ko_4 = '씨족은 매년 유대를 새롭게 하고 소식을 나누기 위해 만났어요.', example_en_5 = 'Membership in a clan creates a broader sense of belonging beyond the immediate family.', example_ko_5 = '씨족 구성원이 되는 것은 직계 가족 너머의 더 넓은 소속감을 만들어요.' WHERE id = 'w_family_C1_30';
UPDATE words SET example_en_2 = 'He left a generous bequest to help fund his grandchildren''s university fees.', example_ko_2 = '그는 손자녀들의 대학 학비를 지원하기 위해 넉넉한 유산을 남겼어요.', example_en_3 = 'Her bequest to the local library was a reflection of her love of reading.', example_ko_3 = '지역 도서관에 대한 그녀의 유산은 독서에 대한 사랑의 반영이었어요.', example_en_4 = 'The family lawyer helped draft the bequest according to her wishes.', example_ko_4 = '가족 변호사는 그녀의 뜻에 따라 유산을 작성하는 데 도움을 줬어요.', example_en_5 = 'A bequest does not need to be large to have a meaningful impact.', example_ko_5 = '유산이 반드시 클 필요는 없어요 — 작더라도 의미 있는 영향을 줄 수 있어요.' WHERE id = 'w_family_C1_31';
UPDATE words SET example_en_2 = 'They maintained an enduring bond despite living on opposite sides of the world.', example_ko_2 = '그들은 세계 반대편에 살면서도 지속적인 유대를 유지했어요.', example_en_3 = 'The enduring bond between twins is often described as extraordinary.', example_ko_3 = '쌍둥이 사이의 지속적인 유대는 종종 비범하다고 묘사돼요.', example_en_4 = 'Her enduring bond with her mother remained the most constant thing in her life.', example_ko_4 = '어머니와의 지속적인 유대는 그녀의 삶에서 가장 변함없는 것이었어요.', example_en_5 = 'Building an enduring bond takes years of honesty and shared experience.', example_ko_5 = '지속적인 유대를 쌓는 데는 수년간의 솔직함과 공유된 경험이 필요해요.' WHERE id = 'w_family_C1_32';
UPDATE words SET example_en_2 = 'She realised her fear of intimacy came from her psychological inheritance.', example_ko_2 = '그녀는 친밀함에 대한 두려움이 심리적 유산에서 비롯됐다는 것을 깨달았어요.', example_en_3 = 'Unpacking psychological inheritance requires both courage and professional guidance.', example_ko_3 = '심리적 유산을 풀어내는 데는 용기와 전문가의 지도가 모두 필요해요.', example_en_4 = 'His anger patterns were part of a psychological inheritance passed from his father.', example_ko_4 = '그의 분노 패턴은 아버지로부터 이어진 심리적 유산의 일부였어요.', example_en_5 = 'Becoming aware of your psychological inheritance is the beginning of change.', example_ko_5 = '심리적 유산을 인식하게 되는 것이 변화의 시작이에요.' WHERE id = 'w_family_C1_33';
UPDATE words SET example_en_2 = 'She rejected the idea that her place was confined to the domestic sphere.', example_ko_2 = '그녀는 자신의 자리가 가정 영역에 국한된다는 생각을 거부했어요.', example_en_3 = 'The domestic sphere became increasingly valued during the industrial era.', example_ko_3 = '가정 영역은 산업화 시대에 점점 더 중시됐어요.', example_en_4 = 'Work within the domestic sphere is often invisible and undervalued.', example_ko_4 = '가정 영역 내의 일은 종종 보이지 않고 저평가돼요.', example_en_5 = 'She studied how the domestic sphere has been defined differently across history.', example_ko_5 = '그녀는 가정 영역이 역사 전반에 걸쳐 어떻게 다르게 정의돼왔는지 연구했어요.' WHERE id = 'w_family_C1_34';
UPDATE words SET example_en_2 = 'Traditional gender roles have been challenged significantly in recent decades.', example_ko_2 = '전통적인 성 역할은 최근 수십 년간 크게 도전받아왔어요.', example_en_3 = 'She tried to raise her children without rigid gender role expectations.', example_ko_3 = '그녀는 경직된 성 역할 기대 없이 자녀들을 키우려 했어요.', example_en_4 = 'Changing gender roles within families is linked to broader social change.', example_ko_4 = '가족 내에서 변화하는 성 역할은 더 넓은 사회 변화와 연결돼 있어요.', example_en_5 = 'He challenged traditional gender roles by becoming the primary caregiver for his children.', example_ko_5 = '그는 자녀들의 주요 돌봄 제공자가 됨으로써 전통적인 성 역할에 도전했어요.' WHERE id = 'w_family_C1_35';

-- C2
UPDATE words SET example_en_2 = 'She studied the history of primogeniture and its impact on family wealth.', example_ko_2 = '그녀는 장자 상속 제도의 역사와 가족 부에 미친 영향을 연구했어요.', example_en_3 = 'Primogeniture was abolished in many countries during the twentieth century.', example_ko_3 = '장자 상속 제도는 20세기에 많은 나라에서 폐지됐어요.', example_en_4 = 'Under primogeniture, younger children often had to make their own way in the world.', example_ko_4 = '장자 상속 제도 하에서 어린 자녀들은 종종 스스로 세상에서 길을 만들어야 했어요.', example_en_5 = 'The shift away from primogeniture changed the nature of inheritance law significantly.', example_ko_5 = '장자 상속 제도에서 벗어나는 것은 상속법의 성격을 크게 바꿔놓았어요.' WHERE id = 'w_family_C2_01';
UPDATE words SET example_en_2 = 'Agnatic descent means that only males carry and transmit family identity.', example_ko_2 = '부계 혈통은 남성만이 가족 정체성을 지니고 전달한다는 것을 의미해요.', example_en_3 = 'In historically agnatic systems, daughters often did not inherit family property.', example_ko_3 = '역사적으로 부계 체계에서 딸들은 종종 가족 재산을 상속받지 못했어요.', example_en_4 = 'She researched agnatic kinship structures in several ancient legal codes.', example_ko_4 = '그녀는 여러 고대 법전에서 부계 친족 구조를 연구했어요.', example_en_5 = 'Agnatic principles continue to influence inheritance law in some regions today.', example_ko_5 = '부계 원칙은 오늘날에도 일부 지역에서 상속법에 영향을 미쳐요.' WHERE id = 'w_family_C2_02';
UPDATE words SET example_en_2 = 'She compared endogamy practices across three different cultural groups.', example_ko_2 = '그녀는 세 가지 다른 문화 집단에 걸친 내혼제 관행을 비교했어요.', example_en_3 = 'Endogamy can reinforce group solidarity but may limit genetic diversity.', example_ko_3 = '내혼제는 집단 결속을 강화할 수 있지만 유전적 다양성을 제한할 수 있어요.', example_en_4 = 'In some communities, endogamy is practised to preserve religious traditions.', example_ko_4 = '일부 공동체에서는 종교 전통을 보존하기 위해 내혼제가 실천돼요.', example_en_5 = 'The anthropology course examined endogamy within kinship theory.', example_ko_5 = '인류학 강좌에서는 친족 이론 내의 내혼제를 검토했어요.' WHERE id = 'w_family_C2_03';
UPDATE words SET example_en_2 = 'Exogamy encourages alliances between different family or clan groups.', example_ko_2 = '외혼제는 다른 가족 또는 씨족 집단 사이의 동맹을 장려해요.', example_en_3 = 'She examined how exogamy shaped social structures in traditional societies.', example_ko_3 = '그녀는 외혼제가 전통 사회에서 사회 구조를 어떻게 형성했는지 검토했어요.', example_en_4 = 'Exogamy rules vary widely between different cultural and religious communities.', example_ko_4 = '외혼제 규칙은 다양한 문화적, 종교적 공동체에 따라 크게 달라요.', example_en_5 = 'The concept of exogamy reflects how marriage connects families and communities.', example_ko_5 = '외혼제 개념은 결혼이 가족과 공동체를 어떻게 연결하는지를 반영해요.' WHERE id = 'w_family_C2_04';
UPDATE words SET example_en_2 = 'In a matrifocal family, the mother holds the central authority.', example_ko_2 = '어머니 중심 가족에서는 어머니가 중심적인 권위를 갖고 있어요.', example_en_3 = 'Matrifocal family structures are more common in certain Caribbean and West African societies.', example_ko_3 = '어머니 중심 가족 구조는 일부 카리브 및 서아프리카 사회에서 더 흔해요.', example_en_4 = 'She studied how matrifocal households differ from matriarchal societies.', example_ko_4 = '그녀는 어머니 중심 가정이 모계 사회와 어떻게 다른지 연구했어요.', example_en_5 = 'In matrifocal settings, women often bear the primary responsibility for child-rearing.', example_ko_5 = '어머니 중심 환경에서는 여성이 종종 양육에 대한 주된 책임을 져요.' WHERE id = 'w_family_C2_05';
UPDATE words SET example_en_2 = 'In a bilateral descent system, both maternal and paternal relatives are recognised equally.', example_ko_2 = '양계 혈통 체계에서는 모계와 부계 친척이 동등하게 인정돼요.', example_en_3 = 'She explained how bilateral descent differs from unilineal systems in her lecture.', example_ko_3 = '그녀는 강의에서 양계 혈통이 단계 체계와 어떻게 다른지 설명했어요.', example_en_4 = 'Bilateral descent allows children to inherit from both sides of their family.', example_ko_4 = '양계 혈통은 자녀들이 가족 양쪽 모두로부터 상속받을 수 있게 해요.', example_en_5 = 'Bilateral descent is the most common system in Western societies today.', example_ko_5 = '양계 혈통은 오늘날 서구 사회에서 가장 흔한 체계예요.' WHERE id = 'w_family_C2_06';
UPDATE words SET example_en_2 = 'The strength of the conjugal bond affects the wellbeing of all family members.', example_ko_2 = '부부 유대의 강도는 모든 가족 구성원의 안녕에 영향을 미쳐요.', example_en_3 = 'She studied how the conjugal bond is maintained across long-distance relationships.', example_ko_3 = '그녀는 장거리 관계에서 부부 유대가 어떻게 유지되는지 연구했어요.', example_en_4 = 'The conjugal bond is recognised legally through the institution of marriage.', example_ko_4 = '부부 유대는 결혼 제도를 통해 법적으로 인정돼요.', example_en_5 = 'A strong conjugal bond provides emotional stability for the children in the family.', example_ko_5 = '강한 부부 유대는 가족 내 아이들에게 정서적 안정을 제공해요.' WHERE id = 'w_family_C2_07';
UPDATE words SET example_en_2 = 'She argued that nuclear ideology ignores the diversity of real families.', example_ko_2 = '그녀는 핵가족 이데올로기가 실제 가족의 다양성을 무시한다고 주장했어요.', example_en_3 = 'Nuclear ideology became dominant in post-war Western societies.', example_ko_3 = '핵가족 이데올로기는 전후 서구 사회에서 지배적이 됐어요.', example_en_4 = 'The textbook challenged nuclear ideology by featuring many types of families.', example_ko_4 = '그 교과서는 다양한 유형의 가족을 소개함으로써 핵가족 이데올로기에 도전했어요.', example_en_5 = 'Nuclear ideology has been criticised for making single-parent and blended families feel marginalised.', example_ko_5 = '핵가족 이데올로기는 한부모 가족과 혼합 가족이 소외감을 느끼게 만든다는 비판을 받아왔어요.' WHERE id = 'w_family_C2_08';
UPDATE words SET example_en_2 = 'His avuncular manner made him easy to talk to at family gatherings.', example_ko_2 = '그의 삼촌 같은 태도는 가족 모임에서 그와 대화하기 쉽게 만들었어요.', example_en_3 = 'She appreciated the avuncular guidance of her uncle during her teenage years.', example_ko_3 = '그녀는 십대 시절 삼촌의 다정하고 배려 깊은 지도에 감사했어요.', example_en_4 = 'An avuncular tone can help defuse tension in difficult family conversations.', example_ko_4 = '삼촌 같은 어조는 어려운 가족 대화에서 긴장을 완화하는 데 도움이 될 수 있어요.', example_en_5 = 'He had an avuncular way of giving advice without making you feel judged.', example_ko_5 = '그는 판단받는 느낌 없이 조언을 주는 삼촌 같은 방식을 갖고 있었어요.' WHERE id = 'w_family_C2_09';
UPDATE words SET example_en_2 = 'She introduced her affinal relatives at the family gathering.', example_ko_2 = '그녀는 가족 모임에서 혼인 친족들을 소개했어요.', example_en_3 = 'Affinal ties created by marriage can be just as close as blood bonds.', example_ko_3 = '결혼으로 맺어진 혼인 유대는 혈연 유대만큼 가까울 수 있어요.', example_en_4 = 'In some cultures, affinal relatives are treated as full members of the family.', example_ko_4 = '일부 문화권에서 혼인 친족은 가족의 완전한 구성원으로 대우받아요.', example_en_5 = 'She studied how affinal relationships are classified across different kinship systems.', example_ko_5 = '그녀는 혼인 관계가 다양한 친족 체계에 걸쳐 어떻게 분류되는지 연구했어요.' WHERE id = 'w_family_C2_10';
UPDATE words SET example_en_2 = 'In most kinship systems, consanguineal bonds are prioritised over affinal ones.', example_ko_2 = '대부분의 친족 체계에서 혈연 유대는 혼인 유대보다 우선시돼요.', example_en_3 = 'She explained the difference between consanguineal and affinal kin to her students.', example_ko_3 = '그녀는 학생들에게 혈연 친족과 혼인 친족의 차이를 설명했어요.', example_en_4 = 'Consanguineal relatives share genetic material as well as social bonds.', example_ko_4 = '혈연 친족은 사회적 유대뿐 아니라 유전 물질을 공유해요.', example_en_5 = 'Legal systems often give priority to consanguineal ties in matters of inheritance.', example_ko_5 = '법적 체계는 상속 문제에서 종종 혈연 유대를 우선시해요.' WHERE id = 'w_family_C2_11';
UPDATE words SET example_en_2 = 'The patrimonial lands had been passed through the family for generations.', example_ko_2 = '가산은 수 세대에 걸쳐 가족을 통해 전해져 왔어요.', example_en_3 = 'She challenged the patrimonial system that excluded daughters from inheriting.', example_ko_3 = '그녀는 딸들을 상속에서 배제하는 가산 제도에 도전했어요.', example_en_4 = 'The patrimonial estate included a farmhouse and several acres of land.', example_ko_4 = '가산에는 농가와 수 에이커의 토지가 포함돼 있었어요.', example_en_5 = 'Disputes over patrimonial inheritance can break families apart permanently.', example_ko_5 = '가산 상속을 둘러싼 분쟁은 가족을 영구적으로 갈라놓을 수 있어요.' WHERE id = 'w_family_C2_12';
UPDATE words SET example_en_2 = 'In societies with matriarchal lineage, women control land and resources.', example_ko_2 = '모계 혈통 사회에서는 여성이 토지와 자원을 통제해요.', example_en_3 = 'She traced her matriarchal lineage back five generations.', example_ko_3 = '그녀는 모계 혈통을 5대까지 거슬러 올라갔어요.', example_en_4 = 'The study compared matriarchal lineage systems in three different cultures.', example_ko_4 = '그 연구는 세 가지 다른 문화에서의 모계 혈통 체계를 비교했어요.', example_en_5 = 'Matriarchal lineage does not always mean women have political power.', example_ko_5 = '모계 혈통이 항상 여성이 정치권력을 갖는다는 것을 의미하지는 않아요.' WHERE id = 'w_family_C2_13';
UPDATE words SET example_en_2 = 'The kinship network mobilised quickly to support the family after the disaster.', example_ko_2 = '친족 네트워크는 재난 후 가족을 지원하기 위해 빠르게 결집했어요.', example_en_3 = 'A wide kinship network can be a powerful safety net in times of hardship.', example_ko_3 = '넓은 친족 네트워크는 어려운 시기에 강력한 안전망이 될 수 있어요.', example_en_4 = 'She mapped her kinship network to understand patterns of support and obligation.', example_ko_4 = '그녀는 지지와 의무의 패턴을 이해하기 위해 친족 네트워크를 지도화했어요.', example_en_5 = 'Immigrant communities often rely heavily on kinship networks for practical help.', example_ko_5 = '이민자 공동체는 실질적인 도움을 위해 친족 네트워크에 크게 의존하는 경우가 많아요.' WHERE id = 'w_family_C2_14';
UPDATE words SET example_en_2 = 'She applied structural functionalism to analyse the division of labour at home.', example_ko_2 = '그녀는 가정에서의 노동 분업을 분석하기 위해 구조 기능주의를 적용했어요.', example_en_3 = 'Critics of structural functionalism argue it ignores conflict and inequality within families.', example_ko_3 = '구조 기능주의 비평가들은 그것이 가족 내의 갈등과 불평등을 무시한다고 주장해요.', example_en_4 = 'Structural functionalism influenced how governments designed family policy for decades.', example_ko_4 = '구조 기능주의는 수십 년 동안 정부가 가족 정책을 설계하는 방식에 영향을 미쳤어요.', example_en_5 = 'The lecture compared structural functionalism with feminist perspectives on the family.', example_ko_5 = '강의에서는 구조 기능주의와 가족에 대한 페미니스트 관점을 비교했어요.' WHERE id = 'w_family_C2_15';
UPDATE words SET example_en_2 = 'Research shows that prolonged attachment disruption leads to difficulties trusting others.', example_ko_2 = '연구에 따르면 장기간의 애착 단절은 타인을 신뢰하는 데 어려움을 유발해요.', example_en_3 = 'She worked with children who had experienced severe attachment disruption.', example_ko_3 = '그녀는 심각한 애착 단절을 경험한 아이들과 함께 일했어요.', example_en_4 = 'Consistent caregiving helps prevent attachment disruption in vulnerable children.', example_ko_4 = '일관적인 돌봄은 취약한 아이들에게 애착 단절이 생기는 것을 예방하는 데 도움이 돼요.', example_en_5 = 'Attachment disruption in early childhood can be addressed through therapeutic intervention.', example_ko_5 = '유아기의 애착 단절은 치료적 개입을 통해 다뤄질 수 있어요.' WHERE id = 'w_family_C2_16';
UPDATE words SET example_en_2 = 'She argued that reproductive labor should be distributed more fairly between partners.', example_ko_2 = '그녀는 재생산 노동이 파트너 간에 더 공정하게 분배되어야 한다고 주장했어요.', example_en_3 = 'Reproductive labor includes all the unseen work of running a household and raising children.', example_ko_3 = '재생산 노동에는 가정을 꾸리고 자녀를 키우는 모든 보이지 않는 일이 포함돼요.', example_en_4 = 'Valuing reproductive labor is a key issue in feminist family sociology.', example_ko_4 = '재생산 노동을 가치 있게 여기는 것은 페미니스트 가족 사회학의 핵심 문제예요.', example_en_5 = 'The unequal distribution of reproductive labor remains a challenge in many households.', example_ko_5 = '재생산 노동의 불균등한 분배는 많은 가정에서 여전히 도전 과제예요.' WHERE id = 'w_family_C2_17';
UPDATE words SET example_en_2 = 'Symbolic interactionism looks at how family members create shared meaning together.', example_ko_2 = '상징적 상호작용론은 가족 구성원들이 함께 공유된 의미를 어떻게 만드는지 살펴봐요.', example_en_3 = 'She used symbolic interactionism to study how families talk about money.', example_ko_3 = '그녀는 가족들이 돈에 대해 어떻게 이야기하는지 연구하기 위해 상징적 상호작용론을 사용했어요.', example_en_4 = 'Symbolic interactionism emphasises how roles and identities are shaped in daily interactions.', example_ko_4 = '상징적 상호작용론은 역할과 정체성이 일상적 상호작용에서 어떻게 형성되는지를 강조해요.', example_en_5 = 'A symbolic interactionist would study how family rituals reinforce shared values.', example_ko_5 = '상징적 상호작용론자는 가족 의례가 공유된 가치를 어떻게 강화하는지 연구할 거예요.' WHERE id = 'w_family_C2_18';
UPDATE words SET example_en_2 = 'Marital dissolution rates vary significantly between countries and age groups.', example_ko_2 = '혼인 해소율은 국가와 연령대에 따라 크게 달라요.', example_en_3 = 'The legal process of marital dissolution can be long and emotionally draining.', example_ko_3 = '혼인 해소의 법적 과정은 길고 감정적으로 지칠 수 있어요.', example_en_4 = 'She studied the effects of marital dissolution on children''s school performance.', example_ko_4 = '그녀는 혼인 해소가 아이들의 학업 성취에 미치는 영향을 연구했어요.', example_en_5 = 'Financial disagreements are one of the leading causes of marital dissolution.', example_ko_5 = '재정적 불일치는 혼인 해소의 주요 원인 중 하나예요.' WHERE id = 'w_family_C2_19';
UPDATE words SET example_en_2 = 'She challenged heteronormative assumptions in her family sociology course.', example_ko_2 = '그녀는 가족 사회학 수업에서 이성애 규범적 가정에 도전했어요.', example_en_3 = 'Heteronormative expectations can make LGBTQ+ family members feel invisible.', example_ko_3 = '이성애 규범적 기대는 LGBTQ+ 가족 구성원들이 보이지 않는 존재처럼 느끼게 만들 수 있어요.', example_en_4 = 'Law and policy have gradually shifted away from heteronormative definitions of family.', example_ko_4 = '법과 정책은 가족에 대한 이성애 규범적 정의에서 점차 벗어나고 있어요.', example_en_5 = 'The textbook critiqued how heteronormative bias shapes family research.', example_ko_5 = '교과서는 이성애 규범적 편향이 가족 연구를 어떻게 형성하는지 비판했어요.' WHERE id = 'w_family_C2_20';
UPDATE words SET example_en_2 = 'She argued that the normative family does not reflect the reality of most households.', example_ko_2 = '그녀는 규범적 가족 모델이 대부분 가정의 현실을 반영하지 않는다고 주장했어요.', example_en_3 = 'The normative family ideal is often promoted through advertising and media.', example_ko_3 = '규범적 가족 이상형은 종종 광고와 미디어를 통해 홍보돼요.', example_en_4 = 'Challenging the normative family model creates space for more inclusive policies.', example_ko_4 = '규범적 가족 모델에 도전하는 것은 더 포용적인 정책을 위한 공간을 만들어요.', example_en_5 = 'The course examined how the normative family has changed over the past century.', example_ko_5 = '강좌에서는 규범적 가족이 지난 세기 동안 어떻게 변해왔는지 검토했어요.' WHERE id = 'w_family_C2_21';
UPDATE words SET example_en_2 = 'Domestic ideology was used to justify limiting women''s access to public roles.', example_ko_2 = '가정 이데올로기는 공적 역할에 대한 여성의 접근을 제한하는 것을 정당화하는 데 사용됐어요.', example_en_3 = 'She analysed how domestic ideology is reinforced through school curricula.', example_ko_3 = '그녀는 가정 이데올로기가 학교 교육과정을 통해 어떻게 강화되는지 분석했어요.', example_en_4 = 'The concept of domestic ideology challenges the idea that family roles are natural.', example_ko_4 = '가정 이데올로기 개념은 가족 역할이 자연스러운 것이라는 생각에 도전해요.', example_en_5 = 'Post-war domestic ideology placed women firmly within the home.', example_ko_5 = '전후 가정 이데올로기는 여성을 가정 내에 확고히 위치시켰어요.' WHERE id = 'w_family_C2_22';
UPDATE words SET example_en_2 = 'Epigenetic research is revealing how ancestral trauma can leave biological marks.', example_ko_2 = '후생유전학 연구는 조상의 트라우마가 어떻게 생물학적 흔적을 남길 수 있는지 밝히고 있어요.', example_en_3 = 'She worked with a therapist to understand and heal her ancestral trauma.', example_ko_3 = '그녀는 치료사와 함께 조상의 트라우마를 이해하고 치유하기 위해 노력했어요.', example_en_4 = 'Ancestral trauma can manifest as anxiety, depression, or relational difficulties.', example_ko_4 = '조상의 트라우마는 불안, 우울증, 또는 관계적 어려움으로 나타날 수 있어요.', example_en_5 = 'Healing ancestral trauma benefits not only individuals but future generations.', example_ko_5 = '조상의 트라우마를 치유하는 것은 개인뿐 아니라 미래 세대에게도 도움이 돼요.' WHERE id = 'w_family_C2_23';
UPDATE words SET example_en_2 = 'Bowen''s family systems theory introduced the concept of emotional fusion in families.', example_ko_2 = '보웬의 가족 체계 이론은 가족 내의 감정적 융합 개념을 도입했어요.', example_en_3 = 'She studied Bowen''s family systems theory to understand her own family dynamics.', example_ko_3 = '그녀는 자신의 가족 역학 관계를 이해하기 위해 보웬의 가족 체계 이론을 공부했어요.', example_en_4 = 'Bowen''s family systems theory emphasises the role of differentiation in healthy families.', example_ko_4 = '보웬의 가족 체계 이론은 건강한 가족에서 자기 분화의 역할을 강조해요.', example_en_5 = 'Therapists trained in Bowen''s family systems theory work with multi-generational patterns.', example_ko_5 = '보웬의 가족 체계 이론을 훈련받은 치료사는 다세대 패턴으로 작업해요.' WHERE id = 'w_family_C2_24';
UPDATE words SET example_en_2 = 'In family triangulation, a child is often caught between two conflicting parents.', example_ko_2 = '가족 내 삼각관계에서는 아이가 종종 갈등하는 두 부모 사이에 끼게 돼요.', example_en_3 = 'Her therapist identified triangulation as a key pattern in her family of origin.', example_ko_3 = '그녀의 치료사는 삼각관계를 그녀의 원가족에서의 핵심 패턴으로 파악했어요.', example_en_4 = 'Triangulation increases tension rather than reducing it in the long run.', example_ko_4 = '삼각관계는 장기적으로 긴장을 줄이기보다 증가시켜요.', example_en_5 = 'Avoiding triangulation requires direct communication between all parties involved.', example_ko_5 = '삼각관계를 피하려면 관련된 모든 당사자 사이의 직접적인 소통이 필요해요.' WHERE id = 'w_family_C2_25';
UPDATE words SET example_en_2 = 'The scapegoating of the eldest child hid deeper problems within the family system.', example_ko_2 = '맏이에 대한 희생양 만들기는 가족 시스템 내의 더 깊은 문제를 숨겼어요.', example_en_3 = 'She realised she had been the scapegoat in her family for most of her childhood.', example_ko_3 = '그녀는 어린 시절 대부분 동안 가족 내에서 희생양이었다는 것을 깨달았어요.', example_en_4 = 'Scapegoating is a way families avoid taking collective responsibility.', example_ko_4 = '희생양 만들기는 가족이 집단적인 책임을 지는 것을 피하는 방법이에요.', example_en_5 = 'Therapy helped her see that scapegoating was not about her but about family dysfunction.', example_ko_5 = '치료가 그녀가 희생양 만들기가 자신에 관한 것이 아니라 가족의 역기능에 관한 것임을 이해하도록 도와줬어요.' WHERE id = 'w_family_C2_26';
UPDATE words SET example_en_2 = 'Emotional cutoff may feel like relief but prevents real connection.', example_ko_2 = '감정적 단절은 안도감처럼 느껴질 수 있지만 진정한 연결을 방해해요.', example_en_3 = 'She engaged in emotional cutoff as a way to manage overwhelming family anxiety.', example_ko_3 = '그녀는 압도적인 가족 불안을 관리하기 위한 방법으로 감정적 단절을 했어요.', example_en_4 = 'Bowen saw emotional cutoff as a sign of unresolved attachment to the family of origin.', example_ko_4 = '보웬은 감정적 단절을 원가족에 대한 해결되지 않은 애착의 신호로 봤어요.', example_en_5 = 'Working through emotional cutoff in therapy can restore healthier family connections.', example_ko_5 = '치료에서 감정적 단절을 해결하면 더 건강한 가족 연결을 회복할 수 있어요.' WHERE id = 'w_family_C2_27';
UPDATE words SET example_en_2 = 'Multigenerational transmission explains why certain family patterns repeat across generations.', example_ko_2 = '다세대 전달 과정은 왜 특정 가족 패턴이 세대에 걸쳐 반복되는지 설명해요.', example_en_3 = 'She studied multigenerational transmission to understand her own emotional patterns.', example_ko_3 = '그녀는 자신의 감정 패턴을 이해하기 위해 다세대 전달 과정을 연구했어요.', example_en_4 = 'Breaking the cycle of multigenerational transmission requires deep self-awareness.', example_ko_4 = '다세대 전달 과정의 순환을 끊으려면 깊은 자기 인식이 필요해요.', example_en_5 = 'Therapists use the concept of multigenerational transmission to map family patterns over time.', example_ko_5 = '치료사들은 시간에 걸친 가족 패턴을 지도화하기 위해 다세대 전달 과정 개념을 사용해요.' WHERE id = 'w_family_C2_28';
UPDATE words SET example_en_2 = 'An undifferentiated person often reacts emotionally rather than thoughtfully.', example_ko_2 = '미분화된 사람은 종종 사려 깊게가 아니라 감정적으로 반응해요.', example_en_3 = 'She realised she had been undifferentiated in her relationship with her mother.', example_ko_3 = '그녀는 어머니와의 관계에서 자신이 미분화된 상태였다는 것을 깨달았어요.', example_en_4 = 'Bowen described undifferentiated family egos as a source of generational dysfunction.', example_ko_4 = '보웬은 미분화된 가족 자아를 세대적 역기능의 원천으로 설명했어요.', example_en_5 = 'Undifferentiated individuals often struggle to maintain stable adult relationships.', example_ko_5 = '미분화된 개인들은 종종 안정적인 성인 관계를 유지하는 데 어려움을 겪어요.' WHERE id = 'w_family_C2_29';
UPDATE words SET example_en_2 = 'Parentification often occurs when a parent struggles with addiction or mental illness.', example_ko_2 = '부모화는 종종 부모가 중독이나 정신 질환으로 어려움을 겪을 때 발생해요.', example_en_3 = 'She did not realise she had been parentified until she started therapy as an adult.', example_ko_3 = '그녀는 성인이 되어 치료를 시작하기 전까지 부모화됐다는 것을 깨닫지 못했어요.', example_en_4 = 'Parentification can leave children feeling responsible for others'' emotions well into adulthood.', example_ko_4 = '부모화는 아이들이 성인이 된 후에도 오랫동안 타인의 감정에 대해 책임감을 느끼게 할 수 있어요.', example_en_5 = 'Healing from parentification involves learning to separate your needs from others''.', example_ko_5 = '부모화로부터의 치유는 자신의 필요를 타인의 것과 분리하는 법을 배우는 것을 포함해요.' WHERE id = 'w_family_C2_30';
UPDATE words SET example_en_2 = 'She sought therapy to overcome the effects of infantilization in her childhood family.', example_ko_2 = '그녀는 어린 시절 가족에서의 유아화 영향을 극복하기 위해 치료를 받기 시작했어요.', example_en_3 = 'Infantilization prevents adults from developing the confidence they need.', example_ko_3 = '유아화는 성인이 필요한 자신감을 키우는 것을 방해해요.', example_en_4 = 'Parents who infantilize their children may do so out of love but it causes harm.', example_ko_4 = '자녀를 유아화하는 부모는 사랑에서 그렇게 할 수 있지만 그것은 해를 끼쳐요.', example_en_5 = 'Infantilization of elderly parents by their children is also a recognised concern.', example_ko_5 = '자녀에 의한 노인 부모의 유아화도 인정된 우려 사항이에요.' WHERE id = 'w_family_C2_31';
UPDATE words SET example_en_2 = 'Role reversal in a family can cause lasting confusion about boundaries and identity.', example_ko_2 = '가족 내의 역할 역전은 경계와 정체성에 대한 지속적인 혼란을 유발할 수 있어요.', example_en_3 = 'She became a caregiver for her mother — a complete role reversal.', example_ko_3 = '그녀는 어머니의 돌봄 제공자가 됐어요 — 완전한 역할 역전이었어요.', example_en_4 = 'Role reversal can damage the parent-child relationship if it is not addressed.', example_ko_4 = '역할 역전은 해결하지 않으면 부모-자녀 관계를 해칠 수 있어요.', example_en_5 = 'In blended families, role reversal between step-parents and children is a common challenge.', example_ko_5 = '혼합 가족에서 계부모와 자녀 사이의 역할 역전은 흔한 도전이에요.' WHERE id = 'w_family_C2_32';
UPDATE words SET example_en_2 = 'A psychodynamic approach looks at how unconscious patterns shape family behaviour.', example_ko_2 = '정신역동적 접근은 무의식적 패턴이 어떻게 가족 행동을 형성하는지 살펴봐요.', example_en_3 = 'She trained in psychodynamic therapy to better help families in conflict.', example_ko_3 = '그녀는 갈등 중인 가족들을 더 잘 돕기 위해 정신역동 치료 훈련을 받았어요.', example_en_4 = 'Psychodynamic theory helps explain why adults unconsciously repeat childhood patterns.', example_ko_4 = '정신역동 이론은 어른들이 왜 무의식적으로 어린 시절 패턴을 반복하는지 설명하는 데 도움이 돼요.', example_en_5 = 'Psychodynamic family therapy can uncover deep-rooted beliefs about love and belonging.', example_ko_5 = '정신역동 가족 치료는 사랑과 소속감에 대한 깊이 뿌리내린 믿음을 밝혀낼 수 있어요.' WHERE id = 'w_family_C2_33';
UPDATE words SET example_en_2 = 'Object relations theory suggests that early family relationships form the template for later ones.', example_ko_2 = '대상 관계 이론은 초기 가족 관계가 이후 관계의 틀을 형성한다고 제안해요.', example_en_3 = 'She found object relations theory helpful for understanding her fear of intimacy.', example_ko_3 = '그녀는 대상 관계 이론이 친밀함에 대한 두려움을 이해하는 데 도움이 된다고 생각했어요.', example_en_4 = 'Object relations theorists focus on the mother-infant bond as the foundation of psychic life.', example_ko_4 = '대상 관계 이론가들은 어머니-영아 유대를 심리적 삶의 기초로 봐요.', example_en_5 = 'Her therapist used an object relations framework to explore her early family experiences.', example_ko_5 = '그녀의 치료사는 초기 가족 경험을 탐구하기 위해 대상 관계 틀을 사용했어요.' WHERE id = 'w_family_C2_34';
UPDATE words SET example_en_2 = 'The teddy bear served as a transitional object that helped the child feel safe at night.', example_ko_2 = '테디 베어는 아이가 밤에 안전함을 느끼도록 도와주는 전이 대상 역할을 했어요.', example_en_3 = 'Winnicott''s concept of the transitional object opened new ways of thinking about childhood.', example_ko_3 = '위니캇의 전이 대상 개념은 어린 시절에 대한 새로운 사고방식을 열었어요.', example_en_4 = 'She researched how the transitional object helps children cope with separation from parents.', example_ko_4 = '그녀는 전이 대상이 아이들이 부모로부터의 분리에 어떻게 대처하도록 도와주는지 연구했어요.', example_en_5 = 'The blanket became a transitional object that the child carried everywhere for two years.', example_ko_5 = '그 담요는 아이가 2년 동안 어디든 들고 다닌 전이 대상이 됐어요.' WHERE id = 'w_family_C2_35';
